//+------------------------------------------------------------------+
//|              EA_01_ORB_OpenRangeBreakout.mq5                      |
//|              NY Session Open Range Breakout - XAUUSD M5           |
//|              Scalping Strategy for New York Session                |
//+------------------------------------------------------------------+
#property copyright "Quant Strategy Lab"
#property version   "1.00"
#property strict
#property description "Open Range Breakout: Captures institutional momentum"
#property description "after the NY session opening range is established."
#property description "Optimized for XAUUSD M5."

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\SymbolInfo.mqh>

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "=== SESSION FILTER (ET/New York Time) ==="
input int    InpSessionStartHour   = 9;    // NY Session Start Hour (ET)
input int    InpSessionStartMin    = 30;   // NY Session Start Minute (ET)
input int    InpSessionEndHour     = 16;   // NY Session End Hour (ET)
input int    InpSessionEndMin      = 0;    // NY Session End Minute (ET)
input int    InpBrokerGMTOffset    = 2;    // Broker GMT Offset (e.g. 2 for GMT+2)

input group "=== OPEN RANGE PARAMETERS ==="
input int    InpRangeCandles       = 6;    // Number of M5 candles for range (3-6)
input double InpBreakoutBuffer     = 0.50; // Breakout buffer in price units (pips filter)
input int    InpATRPeriod          = 14;   // ATR period for volatility filter
input double InpMinATRMultiplier   = 0.5;  // Min ATR range multiplier (filter tiny ranges)
input double InpMaxATRMultiplier   = 3.0;  // Max ATR range multiplier (filter huge ranges)

input group "=== RISK MANAGEMENT ==="
input double InpLotSize            = 0.10; // Fixed lot size
input double InpStopLossPips       = 0.0;  // SL in price (0 = opposite range extreme)
input double InpTakeProfitRR       = 1.5;  // Take Profit as R:R multiple
input int    InpMaxTradesPerDay    = 2;    // Max trades per day
input int    InpMaxSpread          = 50;   // Max spread allowed (points)

input group "=== TRADE SETTINGS ==="
input int    InpMagicNumber        = 100001; // Magic Number
input string InpTradeComment       = "ORB_Strategy"; // Trade comment
input int    InpSlippage           = 30;   // Max slippage (points)

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         trade;
CPositionInfo  posInfo;
CSymbolInfo    symInfo;

// Range tracking
double   g_rangeHigh       = 0.0;
double   g_rangeLow        = 0.0;
bool     g_rangeEstablished = false;
datetime g_rangeStartTime  = 0;
datetime g_rangeEndTime    = 0;
int      g_candlesInRange  = 0;

// Daily tracking
int      g_todayTrades     = 0;
int      g_lastTradeDay    = -1;
bool     g_tradedBreakoutUp   = false;
bool     g_tradedBreakoutDown = false;

// ATR handle
int      g_atrHandle       = INVALID_HANDLE;

//+------------------------------------------------------------------+
//| Convert ET time to broker server time                             |
//+------------------------------------------------------------------+
datetime ETtoBrokerTime(int etHour, int etMin)
  {
   // ET = GMT-5 (standard) or GMT-4 (DST)
   // For simplicity using fixed offset; adjust InpBrokerGMTOffset for your broker
   int etToGMT = 5; // ET is GMT-5 (use 4 for EDT)
   int totalOffsetHours = InpBrokerGMTOffset + etToGMT;

   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   dt.hour = etHour + totalOffsetHours;
   dt.min  = etMin;
   dt.sec  = 0;

   // Handle day overflow
   if(dt.hour >= 24)
     {
      dt.hour -= 24;
      // Note: day overflow not critical for intraday
     }
   if(dt.hour < 0)
     {
      dt.hour += 24;
     }

   return StructToTime(dt);
  }

//+------------------------------------------------------------------+
//| Check if current time is within NY session                        |
//+------------------------------------------------------------------+
bool IsWithinNYSession()
  {
   datetime sessionStart = ETtoBrokerTime(InpSessionStartHour, InpSessionStartMin);
   datetime sessionEnd   = ETtoBrokerTime(InpSessionEndHour, InpSessionEndMin);
   datetime now          = TimeCurrent();

   return (now >= sessionStart && now <= sessionEnd);
  }

//+------------------------------------------------------------------+
//| Check if current time is in range-building phase                  |
//+------------------------------------------------------------------+
bool IsInRangeBuildingPhase()
  {
   datetime rangeStart = ETtoBrokerTime(InpSessionStartHour, InpSessionStartMin);
   int rangeMinutes    = InpRangeCandles * 5; // M5 candles
   datetime rangeEnd   = rangeStart + rangeMinutes * 60;
   datetime now        = TimeCurrent();

   return (now >= rangeStart && now <= rangeEnd);
  }

//+------------------------------------------------------------------+
//| Expert initialization function                                    |
//+------------------------------------------------------------------+
int OnInit()
  {
   // Validate timeframe
   if(_Period != PERIOD_M5)
     {
      Print("WARNING: This EA is optimized for M5 timeframe. Current: ", EnumToString(_Period));
     }

   // Initialize trade object
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   // Initialize symbol info
   symInfo.Name(_Symbol);

   // Create ATR indicator
   g_atrHandle = iATR(_Symbol, PERIOD_M5, InpATRPeriod);
   if(g_atrHandle == INVALID_HANDLE)
     {
      Print("ERROR: Failed to create ATR indicator");
      return INIT_FAILED;
     }

   Print("ORB Strategy initialized on ", _Symbol, " M5");
   Print("NY Session: ", InpSessionStartHour, ":", InpSessionStartMin, " - ",
         InpSessionEndHour, ":", InpSessionEndMin, " ET");

   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//| Expert deinitialization function                                  |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   if(g_atrHandle != INVALID_HANDLE)
      IndicatorRelease(g_atrHandle);
  }

//+------------------------------------------------------------------+
//| Reset daily variables                                             |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades        = 0;
      g_lastTradeDay       = dt.day_of_year;
      g_rangeEstablished   = false;
      g_rangeHigh          = 0.0;
      g_rangeLow           = 0.0;
      g_candlesInRange     = 0;
      g_tradedBreakoutUp   = false;
      g_tradedBreakoutDown = false;
     }
  }

//+------------------------------------------------------------------+
//| Build the opening range                                           |
//+------------------------------------------------------------------+
void BuildRange()
  {
   if(g_rangeEstablished) return;
   if(!IsInRangeBuildingPhase()) return;

   datetime rangeStart = ETtoBrokerTime(InpSessionStartHour, InpSessionStartMin);

   // Count M5 candles since range start
   double high = -DBL_MAX;
   double low  = DBL_MAX;
   int counted = 0;

   for(int i = 0; i < InpRangeCandles + 5; i++) // small buffer
     {
      datetime candleTime = iTime(_Symbol, PERIOD_M5, i);
      if(candleTime < rangeStart) break;

      int rangeMinutes = InpRangeCandles * 5;
      datetime rangeEnd = rangeStart + rangeMinutes * 60;
      if(candleTime >= rangeEnd) continue;

      double h = iHigh(_Symbol, PERIOD_M5, i);
      double l = iLow(_Symbol, PERIOD_M5, i);

      if(h > high) high = h;
      if(l < low)  low  = l;
      counted++;
     }

   if(counted >= InpRangeCandles)
     {
      g_rangeHigh        = high;
      g_rangeLow         = low;
      g_rangeEstablished = true;

      Print("Opening Range Established: High=", g_rangeHigh, " Low=", g_rangeLow,
            " Width=", (g_rangeHigh - g_rangeLow), " Candles=", counted);
     }
  }

//+------------------------------------------------------------------+
//| Validate range with ATR filter                                    |
//+------------------------------------------------------------------+
bool IsRangeValid()
  {
   double atr[];
   ArraySetAsSeries(atr, true);

   if(CopyBuffer(g_atrHandle, 0, 0, 1, atr) <= 0) return false;

   double rangeWidth = g_rangeHigh - g_rangeLow;
   double minRange   = atr[0] * InpMinATRMultiplier;
   double maxRange   = atr[0] * InpMaxATRMultiplier;

   if(rangeWidth < minRange)
     {
      // Range too small - likely no volatility
      return false;
     }
   if(rangeWidth > maxRange)
     {
      // Range too large - already moved
      return false;
     }

   return true;
  }

//+------------------------------------------------------------------+
//| Count open positions for this EA                                  |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(posInfo.SelectByIndex(i))
        {
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
        }
     }
   return count;
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   // Daily reset
   ResetDaily();

   // Update symbol info
   symInfo.RefreshRates();

   // Check spread
   if(symInfo.Spread() > InpMaxSpread) return;

   // Build range during range phase
   if(IsInRangeBuildingPhase() && !g_rangeEstablished)
     {
      BuildRange();
      return;
     }

   // After range phase - look for breakouts
   if(!g_rangeEstablished) return;
   if(!IsWithinNYSession()) return;
   if(IsInRangeBuildingPhase()) return; // Still building

   // Check daily trade limit
   if(g_todayTrades >= InpMaxTradesPerDay) return;

   // Check if we already have a position
   if(CountOpenPositions() > 0) return;

   // Validate range with ATR
   if(!IsRangeValid()) return;

   double ask    = symInfo.Ask();
   double bid    = symInfo.Bid();
   double point  = symInfo.Point();
   double rangeWidth = g_rangeHigh - g_rangeLow;

   // ===== BREAKOUT UP =====
   if(!g_tradedBreakoutUp && ask > (g_rangeHigh + InpBreakoutBuffer))
     {
      double sl = (InpStopLossPips > 0) ? ask - InpStopLossPips : g_rangeLow;
      double slDistance = ask - sl;
      double tp = ask + (slDistance * InpTakeProfitRR);

      // Normalize prices
      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, InpTradeComment + "_LONG"))
        {
         g_todayTrades++;
         g_tradedBreakoutUp = true;
         Print("ORB LONG: Entry=", ask, " SL=", sl, " TP=", tp, " RR=", InpTakeProfitRR);
        }
     }

   // ===== BREAKOUT DOWN =====
   if(!g_tradedBreakoutDown && bid < (g_rangeLow - InpBreakoutBuffer))
     {
      double sl = (InpStopLossPips > 0) ? bid + InpStopLossPips : g_rangeHigh;
      double slDistance = sl - bid;
      double tp = bid - (slDistance * InpTakeProfitRR);

      // Normalize prices
      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, InpTradeComment + "_SHORT"))
        {
         g_todayTrades++;
         g_tradedBreakoutDown = true;
         Print("ORB SHORT: Entry=", bid, " SL=", sl, " TP=", tp, " RR=", InpTakeProfitRR);
        }
     }
  }

//+------------------------------------------------------------------+
//| Close all positions at session end                                |
//+------------------------------------------------------------------+
void CloseAllPositions()
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(posInfo.SelectByIndex(i))
        {
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
           {
            trade.PositionClose(posInfo.Ticket());
           }
        }
     }
  }

//+------------------------------------------------------------------+
//| Timer or session-end check (called from OnTick)                   |
//+------------------------------------------------------------------+
void CheckSessionEnd()
  {
   datetime sessionEnd = ETtoBrokerTime(InpSessionEndHour, InpSessionEndMin);
   if(TimeCurrent() >= sessionEnd)
     {
      CloseAllPositions();
     }
  }
//+------------------------------------------------------------------+

