input group "=== SESSION FILTER (ET/New York Time) ==="
input int    InpSessionStartHour   = 9;    // NY Session Start Hour (ET)
input int    InpSessionStartMin    = 30;   // NY Session Start Minute (ET)
input int    InpSessionEndHour     = 16;   // NY Session End Hour (ET)
input int    InpSessionEndMin      = 0;    // NY Session End Minute (ET)
input int    InpBrokerGMTOffset    = 2;    // Broker GMT Offset

input group "=== FVG DETECTION ==="
input int    InpFVGLookback        = 50;   // Candles to scan for FVGs
input double InpMinFVGSize         = 1.0;  // Minimum FVG size in price units
input double InpMaxFVGSize         = 15.0; // Maximum FVG size (filter news spikes)
input int    InpMaxFVGAge          = 30;   // Max candle age of FVG before expiry

input group "=== LIQUIDITY SWEEP ==="
input int    InpSwingLookback      = 10;   // Candles to define swing High/Low
input double InpSweepMinPips       = 0.5;  // Min sweep beyond swing level
input double InpSweepMaxPips       = 8.0;  // Max sweep (filter breakouts vs sweeps)
input int    InpSweepConfirmBars   = 2;    // Bars to confirm sweep rejection

input group "=== RISK MANAGEMENT ==="
input double InpLotSize            = 0.10; // Fixed lot size
input double InpTakeProfitRR       = 1.5;  // Take Profit R:R ratio
input int    InpMaxTradesPerDay    = 3;    // Max trades per day
input int    InpMaxSpread          = 50;   // Max spread (points)
input int    InpMaxOpenPositions   = 1;    // Max simultaneous positions

input group "=== TRADE SETTINGS ==="
input int    InpMagicNumber        = 100002; // Magic Number
input string InpTradeComment       = "FVG_Sweep"; // Trade comment
input int    InpSlippage           = 30;   // Max slippage (points)

//+------------------------------------------------------------------+
//| STRUCTURES                                                        |
//+------------------------------------------------------------------+
struct FairValueGap
  {
   double   highBound;     // Upper boundary of gap
   double   lowBound;      // Lower boundary of gap
   datetime createTime;    // When FVG was created
   int      createBar;     // Bar index at creation
   int      direction;     // +1 = bullish FVG, -1 = bearish FVG
   bool     filled;        // Has price returned to fill it
   bool     active;        // Still valid for entry
  };

struct SwingPoint
  {
   double   price;
   datetime time;
   int      barIndex;
   int      type;          // +1 = swing high, -1 = swing low
  };

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         trade;
CPositionInfo  posInfo;
CSymbolInfo    symInfo;

FairValueGap   g_fvgs[];
SwingPoint     g_swings[];

int            g_todayTrades  = 0;
int            g_lastTradeDay = -1;

//+------------------------------------------------------------------+
//| Convert ET to broker time                                         |
//+------------------------------------------------------------------+
datetime ETtoBrokerTime(int etHour, int etMin)
  {
   int etToGMT = 5;
   int totalOffset = InpBrokerGMTOffset + etToGMT;

   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   dt.hour = etHour + totalOffset;
   dt.min  = etMin;
   dt.sec  = 0;

   if(dt.hour >= 24) dt.hour -= 24;
   if(dt.hour < 0)   dt.hour += 24;

   return StructToTime(dt);
