   datetime end   = ETtoBrokerTime(InpSessionEndHour, InpSessionEndMin);
   datetime now   = TimeCurrent();
   return (now >= start && now <= end);
  }

//+------------------------------------------------------------------+
//| Expert initialization                                             |
//+------------------------------------------------------------------+
int OnInit()
  {
   if(_Period != PERIOD_M5)
      Print("WARNING: Optimized for M5. Current: ", EnumToString(_Period));

   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   symInfo.Name(_Symbol);

   ArrayResize(g_fvgs, 0);
   ArrayResize(g_swings, 0);

   Print("FVG + Liquidity Sweep Strategy initialized on ", _Symbol);
   return INIT_SUCCEEDED;
  }

//+------------------------------------------------------------------+
//| Detect Fair Value Gaps                                            |
//+------------------------------------------------------------------+
void DetectFVGs()
  {
   // FVG = gap between candle[i-2].high and candle[i].low (bullish)
   //     or gap between candle[i].high and candle[i-2].low (bearish)

   for(int i = 2; i < InpFVGLookback; i++)
     {
      double high0 = iHigh(_Symbol, PERIOD_M5, i);     // Current candle
      double low0  = iLow(_Symbol, PERIOD_M5, i);
      double high2 = iHigh(_Symbol, PERIOD_M5, i + 2); // Two candles back
      double low2  = iLow(_Symbol, PERIOD_M5, i + 2);

      // Check if this FVG already exists
      datetime candleTime = iTime(_Symbol, PERIOD_M5, i);
      bool exists = false;
      for(int j = 0; j < ArraySize(g_fvgs); j++)
        {
         if(g_fvgs[j].createTime == candleTime)
           {
            exists = true;
            break;
           }
        }
      if(exists) continue;

      // ===== BULLISH FVG: gap between candle[i+2].high and candle[i].low =====
      if(low0 > high2)
        {
         double gapSize = low0 - high2;
         if(gapSize >= InpMinFVGSize && gapSize <= InpMaxFVGSize)
           {
            FairValueGap fvg;
            fvg.highBound  = low0;      // Upper edge of gap
            fvg.lowBound   = high2;     // Lower edge of gap
            fvg.createTime = candleTime;
            fvg.createBar  = i;
            fvg.direction  = 1;         // Bullish
            fvg.filled     = false;
            fvg.active     = true;

            int size = ArraySize(g_fvgs);
            ArrayResize(g_fvgs, size + 1);
            g_fvgs[size] = fvg;
           }
        }

      // ===== BEARISH FVG: gap between candle[i].high and candle[i+2].low =====
      if(high0 < low2)
        {
         double gapSize = low2 - high0;
         if(gapSize >= InpMinFVGSize && gapSize <= InpMaxFVGSize)
           {
            FairValueGap fvg;
            fvg.highBound  = low2;      // Upper edge
            fvg.lowBound   = high0;     // Lower edge
            fvg.createTime = candleTime;
            fvg.createBar  = i;
            fvg.direction  = -1;        // Bearish
            fvg.filled     = false;
            fvg.active     = true;

            int size = ArraySize(g_fvgs);
            ArrayResize(g_fvgs, size + 1);
            g_fvgs[size] = fvg;
           }
        }
     }
  }

//+------------------------------------------------------------------+
//| Detect Swing Points                                               |
//+------------------------------------------------------------------+
void DetectSwings()
  {
   ArrayResize(g_swings, 0);

   for(int i = InpSwingLookback; i < InpFVGLookback; i++)
     {
      double high_i = iHigh(_Symbol, PERIOD_M5, i);
      double low_i  = iLow(_Symbol, PERIOD_M5, i);

      // Check swing high
      bool isSwingHigh = true;
      for(int j = 1; j <= InpSwingLookback; j++)
        {
         if(iHigh(_Symbol, PERIOD_M5, i - j) >= high_i ||
            iHigh(_Symbol, PERIOD_M5, i + j) >= high_i)
           {
            isSwingHigh = false;
            break;
           }
        }

      if(isSwingHigh)
        {
         SwingPoint sp;
         sp.price    = high_i;
         sp.time     = iTime(_Symbol, PERIOD_M5, i);
         sp.barIndex = i;
         sp.type     = 1; // Swing high
         int size = ArraySize(g_swings);
         ArrayResize(g_swings, size + 1);
         g_swings[size] = sp;
        }

      // Check swing low
      bool isSwingLow = true;
      for(int j = 1; j <= InpSwingLookback; j++)
        {
         if(iLow(_Symbol, PERIOD_M5, i - j) <= low_i ||
            iLow(_Symbol, PERIOD_M5, i + j) <= low_i)
           {
            isSwingLow = false;
            break;
           }
        }

      if(isSwingLow)
        {
         SwingPoint sp;
         sp.price    = low_i;
         sp.time     = iTime(_Symbol, PERIOD_M5, i);
         sp.barIndex = i;
         sp.type     = -1; // Swing low
         int size = ArraySize(g_swings);
         ArrayResize(g_swings, size + 1);
         g_swings[size] = sp;
        }
     }
  }

//+------------------------------------------------------------------+
//| Check for liquidity sweep of swing high (bearish setup)           |
//+------------------------------------------------------------------+
bool DetectBearishSweep(double &sweepLevel)
  {
   // Price swept above a swing high then rejected back below
   for(int s = 0; s < ArraySize(g_swings); s++)
     {
      if(g_swings[s].type != 1) continue; // Only swing highs

      double swingPrice = g_swings[s].price;

      // Check recent candles for sweep
      for(int i = 0; i < InpSweepConfirmBars + 1; i++)
        {
         double high_i  = iHigh(_Symbol, PERIOD_M5, i);
         double close_i = iClose(_Symbol, PERIOD_M5, i);

         // Wick above swing high (sweep) but closed below
         double sweepAmount = high_i - swingPrice;
         if(sweepAmount >= InpSweepMinPips && sweepAmount <= InpSweepMaxPips)
           {
            if(close_i < swingPrice) // Rejection confirmed
              {
               sweepLevel = swingPrice;
               return true;
              }
           }
        }
     }
   return false;
  }

//+------------------------------------------------------------------+
//| Check for liquidity sweep of swing low (bullish setup)            |
//+------------------------------------------------------------------+
bool DetectBullishSweep(double &sweepLevel)
  {
   for(int s = 0; s < ArraySize(g_swings); s++)
     {
      if(g_swings[s].type != -1) continue; // Only swing lows

      double swingPrice = g_swings[s].price;

      for(int i = 0; i < InpSweepConfirmBars + 1; i++)
        {
         double low_i   = iLow(_Symbol, PERIOD_M5, i);
         double close_i = iClose(_Symbol, PERIOD_M5, i);

         double sweepAmount = swingPrice - low_i;
         if(sweepAmount >= InpSweepMinPips && sweepAmount <= InpSweepMaxPips)
           {
            if(close_i > swingPrice)
              {
               sweepLevel = swingPrice;
               return true;
              }
           }
        }
     }
   return false;
  }

//+------------------------------------------------------------------+
//| Find nearest active FVG for entry                                 |
//+------------------------------------------------------------------+
int FindNearestFVG(int direction, double currentPrice)
  {
   int bestIdx = -1;
   double bestDistance = DBL_MAX;

   for(int i = 0; i < ArraySize(g_fvgs); i++)
     {
      if(!g_fvgs[i].active) continue;
      if(g_fvgs[i].filled) continue;
      if(g_fvgs[i].direction != direction) continue;

      // Check age
      int age = iBarShift(_Symbol, PERIOD_M5, g_fvgs[i].createTime);
      if(age > InpMaxFVGAge)
        {
         g_fvgs[i].active = false;
         continue;
        }

      // Calculate distance to FVG midpoint
      double mid = (g_fvgs[i].highBound + g_fvgs[i].lowBound) / 2.0;
      double dist = MathAbs(currentPrice - mid);

      // Price must be inside or very near the FVG
      if(direction == 1) // Bullish FVG - price entering from above
        {
         if(currentPrice <= g_fvgs[i].highBound && currentPrice >= g_fvgs[i].lowBound)
           {
            if(dist < bestDistance)
              {
               bestDistance = dist;
               bestIdx = i;
              }
           }
        }
      else // Bearish FVG - price entering from below
        {
         if(currentPrice >= g_fvgs[i].lowBound && currentPrice <= g_fvgs[i].highBound)
           {
            if(dist < bestDistance)
              {
               bestDistance = dist;
               bestIdx = i;
              }
           }
        }
     }

   return bestIdx;
  }

//+------------------------------------------------------------------+
//| Update FVG fill status                                            |
//+------------------------------------------------------------------+
void UpdateFVGStatus()
  {
   double bid = symInfo.Bid();

   for(int i = 0; i < ArraySize(g_fvgs); i++)
     {
      if(!g_fvgs[i].active) continue;

      // Mark as filled if price passed through entirely
      if(g_fvgs[i].direction == 1 && bid < g_fvgs[i].lowBound)
         g_fvgs[i].filled = true;
      if(g_fvgs[i].direction == -1 && bid > g_fvgs[i].highBound)
         g_fvgs[i].filled = true;
     }
  }

//+------------------------------------------------------------------+
//| Count open positions                                              |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
     }
   return count;
  }

//+------------------------------------------------------------------+
//| Reset daily counters                                              |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades  = 0;
      g_lastTradeDay = dt.day_of_year;
      ArrayResize(g_fvgs, 0);
      ArrayResize(g_swings, 0);
     }
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   ResetDaily();
   symInfo.RefreshRates();

   if(!IsWithinNYSession()) return;
   if(symInfo.Spread() > InpMaxSpread) return;
   if(g_todayTrades >= InpMaxTradesPerDay) return;
   if(CountOpenPositions() >= InpMaxOpenPositions) return;

   // Detect market structure
   DetectFVGs();
   DetectSwings();
   UpdateFVGStatus();

   double ask = symInfo.Ask();
   double bid = symInfo.Bid();

   // ===== BULLISH SETUP: Sweep of swing low + price enters bullish FVG =====
   double bullSweepLevel = 0;
   if(DetectBullishSweep(bullSweepLevel))
     {
      int fvgIdx = FindNearestFVG(1, bid); // Bullish FVG
      if(fvgIdx >= 0)
        {
         double sl = g_fvgs[fvgIdx].lowBound - InpSweepMaxPips;
         double slDistance = ask - sl;
         double tp = ask + (slDistance * InpTakeProfitRR);

         sl = NormalizeDouble(sl, _Digits);
         tp = NormalizeDouble(tp, _Digits);

         if(slDistance > 0 && trade.Buy(InpLotSize, _Symbol, ask, sl, tp,
            InpTradeComment + "_BUY"))
           {
            g_todayTrades++;
            g_fvgs[fvgIdx].active = false;
            Print("FVG BUY: Sweep at ", bullSweepLevel, " FVG=[",
                  g_fvgs[fvgIdx].lowBound, "-", g_fvgs[fvgIdx].highBound, "]");
           }
        }
     }

   // ===== BEARISH SETUP: Sweep of swing high + price enters bearish FVG =====
   double bearSweepLevel = 0;
   if(DetectBearishSweep(bearSweepLevel))
     {
      int fvgIdx = FindNearestFVG(-1, ask); // Bearish FVG
      if(fvgIdx >= 0)
        {
         double sl = g_fvgs[fvgIdx].highBound + InpSweepMaxPips;
         double slDistance = sl - bid;
         double tp = bid - (slDistance * InpTakeProfitRR);

         sl = NormalizeDouble(sl, _Digits);
         tp = NormalizeDouble(tp, _Digits);

         if(slDistance > 0 && trade.Sell(InpLotSize, _Symbol, bid, sl, tp,
            InpTradeComment + "_SELL"))
           {
            g_todayTrades++;
            g_fvgs[fvgIdx].active = false;
            Print("FVG SELL: Sweep at ", bearSweepLevel, " FVG=[",
                  g_fvgs[fvgIdx].lowBound, "-", g_fvgs[fvgIdx].highBound, "]");
           }
        }
     }
  }

//+------------------------------------------------------------------+
//| Deinit                                                            |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   ArrayFree(g_fvgs);
   ArrayFree(g_swings);
  }
