  {
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   symInfo.Name(_Symbol);

   g_atrFastHandle = iATR(_Symbol, PERIOD_M5, InpATRFast);
   g_atrSlowHandle = iATR(_Symbol, PERIOD_M5, InpATRSlow);
   g_emaHandle     = iMA(_Symbol, PERIOD_M5, InpEMAPeriod, 0, MODE_EMA, PRICE_CLOSE);

   if(g_atrFastHandle == INVALID_HANDLE || g_atrSlowHandle == INVALID_HANDLE ||
      g_emaHandle == INVALID_HANDLE)
     {
      Print("ERROR: Failed to create indicators");
      return INIT_FAILED;
     }

   Print("Volatility Squeeze Strategy initialized on ", _Symbol);
   return INIT_SUCCEEDED;
  }

void OnDeinit(const int reason)
  {
   if(g_atrFastHandle != INVALID_HANDLE) IndicatorRelease(g_atrFastHandle);
   if(g_atrSlowHandle != INVALID_HANDLE) IndicatorRelease(g_atrSlowHandle);
   if(g_emaHandle != INVALID_HANDLE)     IndicatorRelease(g_emaHandle);
  }

//+------------------------------------------------------------------+
//| Get ATR ratio (fast/slow)                                         |
//+------------------------------------------------------------------+
double GetATRRatio(int shift = 0)
  {
   double atrFast[], atrSlow[];
   ArraySetAsSeries(atrFast, true);
   ArraySetAsSeries(atrSlow, true);

   if(CopyBuffer(g_atrFastHandle, 0, shift, 1, atrFast) <= 0) return -1;
   if(CopyBuffer(g_atrSlowHandle, 0, shift, 1, atrSlow) <= 0) return -1;

   if(atrSlow[0] == 0) return -1;
   return atrFast[0] / atrSlow[0];
  }

//+------------------------------------------------------------------+
//| Get directional bias: +1 bullish, -1 bearish, 0 neutral          |
//+------------------------------------------------------------------+
int GetDirectionalBias()
  {
   // Method 1: Close delta over momentum period
   double closeNow  = iClose(_Symbol, PERIOD_M5, 0);
   double closePast = iClose(_Symbol, PERIOD_M5, InpMomentumPeriod);
   double delta     = closeNow - closePast;

   // Method 2: Price vs EMA
   double ema[];
   ArraySetAsSeries(ema, true);
   if(CopyBuffer(g_emaHandle, 0, 0, 1, ema) <= 0) return 0;

   bool aboveEMA = closeNow > ema[0];

   // Both must agree
   if(delta > InpMinMomentumDelta && aboveEMA) return 1;   // Bullish
   if(delta < -InpMinMomentumDelta && !aboveEMA) return -1; // Bearish

   return 0; // No clear direction
  }

//+------------------------------------------------------------------+
//| Get current ATR slow value for SL calculation                     |
//+------------------------------------------------------------------+
double GetATRSlow()
  {
   double atrSlow[];
   ArraySetAsSeries(atrSlow, true);
   if(CopyBuffer(g_atrSlowHandle, 0, 0, 1, atrSlow) <= 0) return 0;
   return atrSlow[0];
  }

//+------------------------------------------------------------------+
//| Count positions                                                   |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   return count;
  }

//+------------------------------------------------------------------+
//| Reset daily                                                       |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades   = 0;
      g_lastTradeDay  = dt.day_of_year;
      g_squeezeState  = STATE_IDLE;
      g_squeezeBars   = 0;
     }
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   ResetDaily();
   symInfo.RefreshRates();

   if(!IsWithinNYSession()) return;
   if(symInfo.Spread() > InpMaxSpread) return;
   if(g_todayTrades >= InpMaxTradesPerDay) return;

   // Only process on new bar
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   double atrRatio = GetATRRatio();
   if(atrRatio < 0) return;

   double ask = symInfo.Ask();
   double bid = symInfo.Bid();

   // ===== STATE MACHINE =====
   switch(g_squeezeState)
     {
      case STATE_IDLE:
         // Look for squeeze entry
         if(atrRatio <= InpSqueezeThreshold)
           {
            g_squeezeState  = STATE_SQUEEZING;
            g_squeezeBars   = 1;
            g_squeezeCenter = (ask + bid) / 2.0;
            Print("SQUEEZE DETECTED: ATR ratio=", DoubleToString(atrRatio, 3));
           }
         break;

      case STATE_SQUEEZING:
         if(atrRatio <= InpSqueezeThreshold)
           {
            g_squeezeBars++;
            // Update center as running average
            g_squeezeCenter = (g_squeezeCenter + (ask + bid) / 2.0) / 2.0;
           }
         else if(atrRatio >= InpExpansionThreshold && g_squeezeBars >= InpMinSqueezeBars)
           {
            // EXPANSION! Time to trade
            Print("EXPANSION FIRED: ATR ratio=", DoubleToString(atrRatio, 3),
                  " after ", g_squeezeBars, " squeeze bars");

            int direction = GetDirectionalBias();

            if(direction != 0 && CountOpenPositions() == 0)
              {
               double atrSlow   = GetATRSlow();
               double slDistance = atrSlow * InpSLMultiplier;

               if(direction == 1) // LONG
                 {
                  double sl = NormalizeDouble(ask - slDistance, _Digits);
                  double tp = NormalizeDouble(ask + slDistance * InpTPRatio, _Digits);

                  if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp,
                     InpTradeComment + "_LONG"))
                    {
                     g_todayTrades++;
                     Print("SQUEEZE LONG: Entry=", ask, " SL=", sl, " TP=", tp);
                    }
                 }
               else // SHORT
                 {
                  double sl = NormalizeDouble(bid + slDistance, _Digits);
                  double tp = NormalizeDouble(bid - slDistance * InpTPRatio, _Digits);

                  if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp,
                     InpTradeComment + "_SHORT"))
                    {
                     g_todayTrades++;
                     Print("SQUEEZE SHORT: Entry=", bid, " SL=", sl, " TP=", tp);
                    }
                 }
              }

            g_squeezeState = STATE_FIRED;
           }
         else if(atrRatio > InpSqueezeThreshold && atrRatio < InpExpansionThreshold)
           {
            // Squeeze broke without strong expansion - reset
            if(g_squeezeBars < InpMinSqueezeBars)
              {
               g_squeezeState = STATE_IDLE;
               g_squeezeBars  = 0;
              }
           }
         break;

      case STATE_FIRED:
         // Wait for positions to close, then reset
         if(CountOpenPositions() == 0)
           {
            g_squeezeState = STATE_IDLE;
            g_squeezeBars  = 0;
           }
         break;
     }
  }
