//+------------------------------------------------------------------+
//|              EA_04_ZScore_MeanReversion.mq5                       |
//|              Z-Score Dynamic Mean Reversion - XAUUSD M5           |
//|              Statistical Mean Reversion with Rolling VWAP          |
//+------------------------------------------------------------------+
#property copyright "Quant Strategy Lab"
#property version   "1.00"
#property strict
#property description "Mean reversion strategy using Z-Score of price"
#property description "relative to rolling VWAP. Enters counter-trend when"
#property description "Z exceeds ±2σ, exits at ±0.5σ. NY Session only."

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\SymbolInfo.mqh>

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "=== SESSION FILTER (ET) ==="
input int    InpSessionStartHour   = 9;
input int    InpSessionStartMin    = 30;
input int    InpSessionEndHour     = 16;
input int    InpSessionEndMin      = 0;
input int    InpBrokerGMTOffset    = 2;

input group "=== Z-SCORE PARAMETERS ==="
input int    InpVWAPPeriod         = 20;   // Rolling VWAP lookback (bars)
input double InpEntryZScore        = 2.0;  // Z-Score entry threshold
input double InpExitZScore         = 0.5;  // Z-Score exit threshold (return to mean)
input double InpStopZScore         = 3.0;  // Z-Score stop loss threshold
input int    InpStdDevPeriod       = 20;   // Std deviation calculation period

input group "=== ADDITIONAL FILTERS ==="
input int    InpMinVolumePeriod    = 20;   // Volume comparison period
input double InpMinVolumeRatio     = 0.8;  // Min volume ratio vs average
input int    InpATRPeriod          = 14;   // ATR for volatility context
input double InpMinATR             = 1.0;  // Minimum ATR for entry (avoid flat market)

input group "=== RISK MANAGEMENT ==="
input double InpLotSize            = 0.10;
input double InpFixedSL            = 0.0;  // Fixed SL in price (0 = use Z-Score SL)
input double InpTakeProfitRR       = 0.0;  // Fixed TP as RR (0 = use Z-Score exit)
input int    InpMaxTradesPerDay    = 4;
input int    InpMaxSpread          = 50;
input int    InpMaxBarsInTrade     = 30;   // Max bars before forced exit

input group "=== TRADE SETTINGS ==="
input int    InpMagicNumber        = 100004;
input string InpTradeComment       = "ZScore_MR";
input int    InpSlippage           = 30;

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         trade;
CPositionInfo  posInfo;
CSymbolInfo    symInfo;

int            g_atrHandle     = INVALID_HANDLE;
int            g_todayTrades   = 0;
int            g_lastTradeDay  = -1;
datetime       g_entryBarTime  = 0;

//+------------------------------------------------------------------+
//| ET to Broker time                                                 |
//+------------------------------------------------------------------+
datetime ETtoBrokerTime(int etHour, int etMin)
  {
   int totalOffset = InpBrokerGMTOffset + 5;
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   dt.hour = etHour + totalOffset;
   dt.min  = etMin;
   dt.sec  = 0;
   if(dt.hour >= 24) dt.hour -= 24;
   if(dt.hour < 0)   dt.hour += 24;
   return StructToTime(dt);
  }

bool IsWithinNYSession()
  {
   datetime start = ETtoBrokerTime(InpSessionStartHour, InpSessionStartMin);
   datetime end   = ETtoBrokerTime(InpSessionEndHour, InpSessionEndMin);
   datetime now   = TimeCurrent();
   return (now >= start && now <= end);
  }

//+------------------------------------------------------------------+
//| Init                                                              |
//+------------------------------------------------------------------+
int OnInit()
  {
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   symInfo.Name(_Symbol);

   g_atrHandle = iATR(_Symbol, PERIOD_M5, InpATRPeriod);
   if(g_atrHandle == INVALID_HANDLE)
     {
      Print("ERROR: Failed to create ATR indicator");
      return INIT_FAILED;
     }

   Print("Z-Score Mean Reversion Strategy initialized on ", _Symbol);
   return INIT_SUCCEEDED;
  }

void OnDeinit(const int reason)
  {
   if(g_atrHandle != INVALID_HANDLE) IndicatorRelease(g_atrHandle);
  }

//+------------------------------------------------------------------+
//| Calculate Rolling VWAP                                            |
//+------------------------------------------------------------------+
double CalcRollingVWAP(int period)
  {
   double sumPV = 0.0; // Sum of Price * Volume
   double sumV  = 0.0; // Sum of Volume

   for(int i = 0; i < period; i++)
     {
      double typical = (iHigh(_Symbol, PERIOD_M5, i) + 
                        iLow(_Symbol, PERIOD_M5, i) + 
                        iClose(_Symbol, PERIOD_M5, i)) / 3.0;
      long   vol     = iVolume(_Symbol, PERIOD_M5, i);

      // Use tick volume as proxy (standard for forex/CFDs)
      double volume = (double)vol;
      if(volume <= 0) volume = 1.0;

      sumPV += typical * volume;
      sumV  += volume;
     }

   if(sumV == 0) return 0;
   return sumPV / sumV;
  }

//+------------------------------------------------------------------+
//| Calculate Z-Score of current price vs VWAP                        |
//+------------------------------------------------------------------+
double CalcZScore()
  {
   double vwap = CalcRollingVWAP(InpVWAPPeriod);
   if(vwap == 0) return 0;

   // Calculate standard deviation of price around VWAP
   double sumSqDev = 0.0;
   for(int i = 0; i < InpStdDevPeriod; i++)
     {
      double typical = (iHigh(_Symbol, PERIOD_M5, i) + 
                        iLow(_Symbol, PERIOD_M5, i) + 
                        iClose(_Symbol, PERIOD_M5, i)) / 3.0;
      double dev = typical - vwap;
      sumSqDev += dev * dev;
     }

   double stdDev = MathSqrt(sumSqDev / InpStdDevPeriod);
   if(stdDev == 0) return 0;

   double currentPrice = (symInfo.Ask() + symInfo.Bid()) / 2.0;
   double zScore = (currentPrice - vwap) / stdDev;

   return zScore;
  }

//+------------------------------------------------------------------+
//| Check volume filter                                               |
//+------------------------------------------------------------------+
bool IsVolumeAdequate()
  {
   long currentVol = iVolume(_Symbol, PERIOD_M5, 0);

   double avgVol = 0;
   for(int i = 1; i <= InpMinVolumePeriod; i++)
      avgVol += (double)iVolume(_Symbol, PERIOD_M5, i);
   avgVol /= InpMinVolumePeriod;

   if(avgVol == 0) return true;
   return ((double)currentVol / avgVol) >= InpMinVolumeRatio;
  }

//+------------------------------------------------------------------+
//| Check ATR filter                                                  |
//+------------------------------------------------------------------+
bool IsVolatilityAdequate()
  {
   double atr[];
   ArraySetAsSeries(atr, true);
   if(CopyBuffer(g_atrHandle, 0, 0, 1, atr) <= 0) return false;
   return atr[0] >= InpMinATR;
  }

//+------------------------------------------------------------------+
//| Count positions & get position info                               |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   return count;
  }

bool SelectMyPosition()
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            return true;
   return false;
  }

//+------------------------------------------------------------------+
//| Reset daily                                                       |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades  = 0;
      g_lastTradeDay = dt.day_of_year;
     }
  }

//+------------------------------------------------------------------+
//| Manage open position (Z-Score based exit)                         |
//+------------------------------------------------------------------+
void ManagePosition()
  {
   if(!SelectMyPosition()) return;

   double zScore = CalcZScore();
   ENUM_POSITION_TYPE posType = posInfo.PositionType();

   bool shouldClose = false;
   string reason = "";

   // Z-Score mean reversion exit
   if(posType == POSITION_TYPE_BUY && zScore >= -InpExitZScore)
     {
      shouldClose = true;
      reason = "Z-Score exit (reverted to mean)";
     }
   if(posType == POSITION_TYPE_SELL && zScore <= InpExitZScore)
     {
      shouldClose = true;
      reason = "Z-Score exit (reverted to mean)";
     }

   // Z-Score stop (extreme extension)
   if(posType == POSITION_TYPE_BUY && zScore < -InpStopZScore)
     {
      shouldClose = true;
      reason = "Z-Score stop (extended further)";
     }
   if(posType == POSITION_TYPE_SELL && zScore > InpStopZScore)
     {
      shouldClose = true;
      reason = "Z-Score stop (extended further)";
     }

   // Time-based exit
   if(InpMaxBarsInTrade > 0 && g_entryBarTime > 0)
     {
      int barsInTrade = iBarShift(_Symbol, PERIOD_M5, g_entryBarTime);
      if(barsInTrade >= InpMaxBarsInTrade)
        {
         shouldClose = true;
         reason = "Max bars timeout (" + IntegerToString(barsInTrade) + " bars)";
        }
     }

   // Session end exit
   if(!IsWithinNYSession())
     {
      shouldClose = true;
      reason = "Session end";
     }

   if(shouldClose)
     {
      trade.PositionClose(posInfo.Ticket());
      Print("ZSCORE EXIT: ", reason, " Z=", DoubleToString(zScore, 2));
      g_entryBarTime = 0;
     }
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   ResetDaily();
   symInfo.RefreshRates();

   // Always manage existing positions
   if(CountOpenPositions() > 0)
     {
      ManagePosition();
      return;
     }

   // New entry logic
   if(!IsWithinNYSession()) return;
   if(symInfo.Spread() > InpMaxSpread) return;
   if(g_todayTrades >= InpMaxTradesPerDay) return;

   // Only on new bar
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   // Filters
   if(!IsVolumeAdequate()) return;
   if(!IsVolatilityAdequate()) return;

   double zScore = CalcZScore();
   double ask    = symInfo.Ask();
   double bid    = symInfo.Bid();
   double vwap   = CalcRollingVWAP(InpVWAPPeriod);

   // ===== LONG: Z-Score <= -Entry threshold (price far below VWAP) =====
   if(zScore <= -InpEntryZScore)
     {
      double sl, tp;

      if(InpFixedSL > 0)
        {
         sl = ask - InpFixedSL;
         tp = (InpTakeProfitRR > 0) ? ask + InpFixedSL * InpTakeProfitRR : vwap;
        }
      else
        {
         // Dynamic SL based on Z-Score distance
         double atr[];
         ArraySetAsSeries(atr, true);
         CopyBuffer(g_atrHandle, 0, 0, 1, atr);

         sl = ask - atr[0] * 2.0;
         tp = vwap; // Target = VWAP (mean)
        }

      // Ensure minimum RR of 1:1
      double slDist = ask - sl;
      double tpDist = tp - ask;
      if(tpDist < slDist) tp = ask + slDist; // Force minimum 1:1

      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, InpTradeComment + "_LONG"))
        {
         g_todayTrades++;
         g_entryBarTime = currentBar;
         Print("ZSCORE LONG: Z=", DoubleToString(zScore, 2), " VWAP=", vwap,
               " Entry=", ask, " SL=", sl, " TP=", tp);
        }
     }

   // ===== SHORT: Z-Score >= +Entry threshold (price far above VWAP) =====
   if(zScore >= InpEntryZScore)
     {
      double sl, tp;

      if(InpFixedSL > 0)
        {
         sl = bid + InpFixedSL;
         tp = (InpTakeProfitRR > 0) ? bid - InpFixedSL * InpTakeProfitRR : vwap;
        }
      else
        {
         double atr[];
         ArraySetAsSeries(atr, true);
         CopyBuffer(g_atrHandle, 0, 0, 1, atr);

         sl = bid + atr[0] * 2.0;
         tp = vwap;
        }

      double slDist = sl - bid;
      double tpDist = bid - tp;
      if(tpDist < slDist) tp = bid - slDist;

      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, InpTradeComment + "_SHORT"))
        {
         g_todayTrades++;
         g_entryBarTime = currentBar;
         Print("ZSCORE SHORT: Z=", DoubleToString(zScore, 2), " VWAP=", vwap,
               " Entry=", bid, " SL=", sl, " TP=", tp);
        }
     }
  }
