   double sumV  = 0.0; // Sum of Volume

   for(int i = 0; i < period; i++)
     {
      double typical = (iHigh(_Symbol, PERIOD_M5, i) + 
                        iLow(_Symbol, PERIOD_M5, i) + 
                        iClose(_Symbol, PERIOD_M5, i)) / 3.0;
      long   vol     = iVolume(_Symbol, PERIOD_M5, i);

      // Use tick volume as proxy (standard for forex/CFDs)
      double volume = (double)vol;
      if(volume <= 0) volume = 1.0;

      sumPV += typical * volume;
      sumV  += volume;
     }

   if(sumV == 0) return 0;
   return sumPV / sumV;
  }

//+------------------------------------------------------------------+
//| Calculate Z-Score of current price vs VWAP                        |
//+------------------------------------------------------------------+
double CalcZScore()
  {
   double vwap = CalcRollingVWAP(InpVWAPPeriod);
   if(vwap == 0) return 0;

   // Calculate standard deviation of price around VWAP
   double sumSqDev = 0.0;
   for(int i = 0; i < InpStdDevPeriod; i++)
     {
      double typical = (iHigh(_Symbol, PERIOD_M5, i) + 
                        iLow(_Symbol, PERIOD_M5, i) + 
                        iClose(_Symbol, PERIOD_M5, i)) / 3.0;
      double dev = typical - vwap;
      sumSqDev += dev * dev;
     }

   double stdDev = MathSqrt(sumSqDev / InpStdDevPeriod);
   if(stdDev == 0) return 0;

   double currentPrice = (symInfo.Ask() + symInfo.Bid()) / 2.0;
   double zScore = (currentPrice - vwap) / stdDev;

   return zScore;
  }

//+------------------------------------------------------------------+
//| Check volume filter                                               |
//+------------------------------------------------------------------+
bool IsVolumeAdequate()
  {
   long currentVol = iVolume(_Symbol, PERIOD_M5, 0);

   double avgVol = 0;
   for(int i = 1; i <= InpMinVolumePeriod; i++)
      avgVol += (double)iVolume(_Symbol, PERIOD_M5, i);
   avgVol /= InpMinVolumePeriod;

   if(avgVol == 0) return true;
   return ((double)currentVol / avgVol) >= InpMinVolumeRatio;
  }

//+------------------------------------------------------------------+
//| Check ATR filter                                                  |
//+------------------------------------------------------------------+
bool IsVolatilityAdequate()
  {
   double atr[];
   ArraySetAsSeries(atr, true);
   if(CopyBuffer(g_atrHandle, 0, 0, 1, atr) <= 0) return false;
   return atr[0] >= InpMinATR;
  }

//+------------------------------------------------------------------+
//| Count positions & get position info                               |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   return count;
  }

bool SelectMyPosition()
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            return true;
   return false;
  }

//+------------------------------------------------------------------+
//| Reset daily                                                       |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades  = 0;
      g_lastTradeDay = dt.day_of_year;
     }
  }

//+------------------------------------------------------------------+
//| Manage open position (Z-Score based exit)                         |
//+------------------------------------------------------------------+
void ManagePosition()
  {
   if(!SelectMyPosition()) return;

   double zScore = CalcZScore();
   ENUM_POSITION_TYPE posType = posInfo.PositionType();

   bool shouldClose = false;
   string reason = "";

   // Z-Score mean reversion exit
   if(posType == POSITION_TYPE_BUY && zScore >= -InpExitZScore)
     {
      shouldClose = true;
      reason = "Z-Score exit (reverted to mean)";
     }
   if(posType == POSITION_TYPE_SELL && zScore <= InpExitZScore)
     {
      shouldClose = true;
      reason = "Z-Score exit (reverted to mean)";
     }

   // Z-Score stop (extreme extension)
   if(posType == POSITION_TYPE_BUY && zScore < -InpStopZScore)
     {
      shouldClose = true;
      reason = "Z-Score stop (extended further)";
     }
   if(posType == POSITION_TYPE_SELL && zScore > InpStopZScore)
     {
      shouldClose = true;
      reason = "Z-Score stop (extended further)";
     }

   // Time-based exit
   if(InpMaxBarsInTrade > 0 && g_entryBarTime > 0)
     {
      int barsInTrade = iBarShift(_Symbol, PERIOD_M5, g_entryBarTime);
      if(barsInTrade >= InpMaxBarsInTrade)
        {
         shouldClose = true;
         reason = "Max bars timeout (" + IntegerToString(barsInTrade) + " bars)";
        }
     }

   // Session end exit
   if(!IsWithinNYSession())
     {
      shouldClose = true;
      reason = "Session end";
     }

   if(shouldClose)
     {
      trade.PositionClose(posInfo.Ticket());
      Print("ZSCORE EXIT: ", reason, " Z=", DoubleToString(zScore, 2));
      g_entryBarTime = 0;
     }
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   ResetDaily();
   symInfo.RefreshRates();

   // Always manage existing positions
   if(CountOpenPositions() > 0)
     {
      ManagePosition();
      return;
     }

   // New entry logic
   if(!IsWithinNYSession()) return;
   if(symInfo.Spread() > InpMaxSpread) return;
   if(g_todayTrades >= InpMaxTradesPerDay) return;

   // Only on new bar
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   // Filters
   if(!IsVolumeAdequate()) return;
   if(!IsVolatilityAdequate()) return;

   double zScore = CalcZScore();
   double ask    = symInfo.Ask();
   double bid    = symInfo.Bid();
   double vwap   = CalcRollingVWAP(InpVWAPPeriod);

   // ===== LONG: Z-Score <= -Entry threshold (price far below VWAP) =====
   if(zScore <= -InpEntryZScore)
     {
      double sl, tp;

      if(InpFixedSL > 0)
        {
         sl = ask - InpFixedSL;
         tp = (InpTakeProfitRR > 0) ? ask + InpFixedSL * InpTakeProfitRR : vwap;
        }
      else
        {
         // Dynamic SL based on Z-Score distance
         double atr[];
         ArraySetAsSeries(atr, true);
         CopyBuffer(g_atrHandle, 0, 0, 1, atr);

         sl = ask - atr[0] * 2.0;
         tp = vwap; // Target = VWAP (mean)
        }

      // Ensure minimum RR of 1:1
      double slDist = ask - sl;
      double tpDist = tp - ask;
      if(tpDist < slDist) tp = ask + slDist; // Force minimum 1:1

      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, InpTradeComment + "_LONG"))
        {
         g_todayTrades++;
         g_entryBarTime = currentBar;
         Print("ZSCORE LONG: Z=", DoubleToString(zScore, 2), " VWAP=", vwap,
               " Entry=", ask, " SL=", sl, " TP=", tp);
        }
     }

   // ===== SHORT: Z-Score >= +Entry threshold (price far above VWAP) =====
   if(zScore >= InpEntryZScore)
     {
      double sl, tp;

      if(InpFixedSL > 0)
        {
         sl = bid + InpFixedSL;
         tp = (InpTakeProfitRR > 0) ? bid - InpFixedSL * InpTakeProfitRR : vwap;
        }
      else
        {
         double atr[];
         ArraySetAsSeries(atr, true);
         CopyBuffer(g_atrHandle, 0, 0, 1, atr);

         sl = bid + atr[0] * 2.0;
         tp = vwap;
        }

      double slDist = sl - bid;
      double tpDist = bid - tp;
      if(tpDist < slDist) tp = bid - slDist;

      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, InpTradeComment + "_SHORT"))
        {
         g_todayTrades++;
         g_entryBarTime = currentBar;
         Print("ZSCORE SHORT: Z=", DoubleToString(zScore, 2), " VWAP=", vwap,
               " Entry=", bid, " SL=", sl, " TP=", tp);
        }
     }
  }
