input int    InpSessionStartMin    = 30;
input int    InpSessionEndHour     = 16;
input int    InpSessionEndMin      = 0;
input int    InpBrokerGMTOffset    = 2;

input group "=== M15 MOMENTUM (Higher TF Bias) ==="
input int    InpROCPeriod          = 4;    // ROC lookback on M15 (periods)
input double InpROCThreshold       = 2.0;  // Min ROC value for strong momentum
input int    InpM15TrendBars       = 3;    // Consecutive M15 bars confirming trend

input group "=== M5 FRACTAL ENTRY ==="
input int    InpFractalBars        = 3;    // Bars on each side for fractal (Williams)
input double InpPullbackMinPct     = 0.25; // Min pullback % of M15 move
input double InpPullbackMaxPct     = 0.70; // Max pullback % (avoid full retracement)
input int    InpMaxEntryDelay      = 6;    // Max M5 bars after fractal for entry

input group "=== RISK MANAGEMENT ==="
input double InpLotSize            = 0.10;
input double InpTakeProfitRR       = 1.5;  // R:R ratio
input int    InpMaxTradesPerDay    = 3;
input int    InpMaxSpread          = 50;
input double InpTrailActivateRR    = 1.0;  // Activate trail at this RR
input double InpTrailStepPips      = 1.0;  // Trail step in price units

input group "=== TRADE SETTINGS ==="
input int    InpMagicNumber        = 100005;
input string InpTradeComment       = "MTF_Cascade";
input int    InpSlippage           = 30;

//+------------------------------------------------------------------+
//| STRUCTURES                                                        |
//+------------------------------------------------------------------+
struct FractalPoint
  {
   double   price;
   datetime time;
   int      barIndex;
   int      type;       // +1 = fractal high, -1 = fractal low
   bool     used;       // Already used for entry
  };

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         trade;
CPositionInfo  posInfo;
CSymbolInfo    symInfo;

FractalPoint   g_fractals[];
int            g_todayTrades   = 0;
int            g_lastTradeDay  = -1;

// M15 momentum state
int            g_m15Direction  = 0;     // +1 bullish, -1 bearish
double         g_m15SwingHigh  = 0;
double         g_m15SwingLow   = 0;

//+------------------------------------------------------------------+
//| ET to Broker time                                                 |
//+------------------------------------------------------------------+
datetime ETtoBrokerTime(int etHour, int etMin)
  {
   int totalOffset = InpBrokerGMTOffset + 5;
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   dt.hour = etHour + totalOffset;
   dt.min  = etMin;
   dt.sec  = 0;
   if(dt.hour >= 24) dt.hour -= 24;
   if(dt.hour < 0)   dt.hour += 24;
   return StructToTime(dt);
  }

bool IsWithinNYSession()
  {
   datetime start = ETtoBrokerTime(InpSessionStartHour, InpSessionStartMin);
   datetime end   = ETtoBrokerTime(InpSessionEndHour, InpSessionEndMin);
   return (TimeCurrent() >= start && TimeCurrent() <= end);
  }

//+------------------------------------------------------------------+
//| Init                                                              |
//+------------------------------------------------------------------+
int OnInit()
  {
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);
   symInfo.Name(_Symbol);

   ArrayResize(g_fractals, 0);

   Print("MTF Momentum Cascade Strategy initialized on ", _Symbol);
   return INIT_SUCCEEDED;
  }

void OnDeinit(const int reason)
  {
   ArrayFree(g_fractals);
  }

//+------------------------------------------------------------------+
//| Calculate Rate of Change on M15                                   |
//+------------------------------------------------------------------+
double CalcM15ROC()
  {
   double closeNow  = iClose(_Symbol, PERIOD_M15, 0);
   double closePast = iClose(_Symbol, PERIOD_M15, InpROCPeriod);

   if(closePast == 0) return 0;
   return ((closeNow - closePast) / closePast) * 100.0;
  }

//+------------------------------------------------------------------+
//| Analyze M15 momentum direction                                    |
//+------------------------------------------------------------------+
int AnalyzeM15Momentum()
  {
   double roc = CalcM15ROC();

   // Check for strong momentum
   if(MathAbs(roc) < InpROCThreshold) return 0;

   // Confirm with consecutive bars
   int direction = (roc > 0) ? 1 : -1;

   for(int i = 0; i < InpM15TrendBars; i++)
     {
      double c = iClose(_Symbol, PERIOD_M15, i);
      double o = iOpen(_Symbol, PERIOD_M15, i);

      if(direction == 1 && c <= o) return 0;  // Need bullish candles
      if(direction == -1 && c >= o) return 0;  // Need bearish candles
     }

   // Calculate swing reference points on M15
   if(direction == 1)
     {
      g_m15SwingLow  = iLow(_Symbol, PERIOD_M15, InpROCPeriod);
      g_m15SwingHigh = iHigh(_Symbol, PERIOD_M15, 0);

      // Find actual low in the lookback
      for(int i = 0; i <= InpROCPeriod; i++)
        {
         double l = iLow(_Symbol, PERIOD_M15, i);
         if(l < g_m15SwingLow) g_m15SwingLow = l;
        }
     }
   else
     {
      g_m15SwingHigh = iHigh(_Symbol, PERIOD_M15, InpROCPeriod);
      g_m15SwingLow  = iLow(_Symbol, PERIOD_M15, 0);

      for(int i = 0; i <= InpROCPeriod; i++)
        {
         double h = iHigh(_Symbol, PERIOD_M15, i);
         if(h > g_m15SwingHigh) g_m15SwingHigh = h;
        }
     }

   return direction;
  }

//+------------------------------------------------------------------+
//| Detect M5 Fractals (Williams fractals)                            |
//+------------------------------------------------------------------+
void DetectM5Fractals()
  {
   ArrayResize(g_fractals, 0);
   int n = InpFractalBars;

   for(int i = n; i < 30; i++) // Scan recent 30 bars
     {
      double high_i = iHigh(_Symbol, PERIOD_M5, i);
      double low_i  = iLow(_Symbol, PERIOD_M5, i);

      // Fractal High: highest of 2n+1 bars centered on i
      bool isFractalHigh = true;
      for(int j = 1; j <= n; j++)
        {
         if(iHigh(_Symbol, PERIOD_M5, i - j) >= high_i) { isFractalHigh = false; break; }
         if(iHigh(_Symbol, PERIOD_M5, i + j) >= high_i) { isFractalHigh = false; break; }
        }

      if(isFractalHigh)
        {
         FractalPoint fp;
         fp.price    = high_i;
         fp.time     = iTime(_Symbol, PERIOD_M5, i);
         fp.barIndex = i;
         fp.type     = 1;
         fp.used     = false;
         int sz = ArraySize(g_fractals);
         ArrayResize(g_fractals, sz + 1);
         g_fractals[sz] = fp;
        }

      // Fractal Low
      bool isFractalLow = true;
      for(int j = 1; j <= n; j++)
        {
         if(iLow(_Symbol, PERIOD_M5, i - j) <= low_i) { isFractalLow = false; break; }
         if(iLow(_Symbol, PERIOD_M5, i + j) <= low_i) { isFractalLow = false; break; }
        }

      if(isFractalLow)
        {
         FractalPoint fp;
         fp.price    = low_i;
         fp.time     = iTime(_Symbol, PERIOD_M5, i);
         fp.barIndex = i;
         fp.type     = -1;
         fp.used     = false;
         int sz = ArraySize(g_fractals);
         ArrayResize(g_fractals, sz + 1);
         g_fractals[sz] = fp;
        }
     }
  }

//+------------------------------------------------------------------+
//| Check pullback depth relative to M15 move                        |
//+------------------------------------------------------------------+
bool IsPullbackValid(double fractalPrice, int direction)
  {
   double m15Range = g_m15SwingHigh - g_m15SwingLow;
   if(m15Range <= 0) return false;

   double pullbackDepth;
   if(direction == 1) // Bullish - pullback is measured from high
      pullbackDepth = (g_m15SwingHigh - fractalPrice) / m15Range;
   else               // Bearish - pullback from low
      pullbackDepth = (fractalPrice - g_m15SwingLow) / m15Range;

   return (pullbackDepth >= InpPullbackMinPct && pullbackDepth <= InpPullbackMaxPct);
  }

//+------------------------------------------------------------------+
//| Find entry fractal aligned with M15 direction                     |
//+------------------------------------------------------------------+
int FindEntryFractal(int m15Dir)
  {
   double currentPrice = (symInfo.Ask() + symInfo.Bid()) / 2.0;

   for(int i = 0; i < ArraySize(g_fractals); i++)
     {
      if(g_fractals[i].used) continue;
      if(g_fractals[i].barIndex > InpMaxEntryDelay) continue;

      if(m15Dir == 1 && g_fractals[i].type == -1) // Bullish: look for fractal LOW (pullback bottom)
        {
         // Price should have bounced from fractal low
         if(currentPrice > g_fractals[i].price)
           {
            if(IsPullbackValid(g_fractals[i].price, 1))
               return i;
           }
        }

      if(m15Dir == -1 && g_fractals[i].type == 1) // Bearish: look for fractal HIGH (pullback top)
        {
         if(currentPrice < g_fractals[i].price)
           {
            if(IsPullbackValid(g_fractals[i].price, -1))
               return i;
           }
        }
     }

   return -1;
  }

//+------------------------------------------------------------------+
//| Count positions                                                   |
//+------------------------------------------------------------------+
int CountOpenPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   return count;
  }

//+------------------------------------------------------------------+
//| Trailing stop management                                          |
//+------------------------------------------------------------------+
void ManageTrailingStop()
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(!posInfo.SelectByIndex(i)) continue;
      if(posInfo.Magic() != InpMagicNumber || posInfo.Symbol() != _Symbol) continue;

      double openPrice = posInfo.PriceOpen();
      double sl        = posInfo.StopLoss();
      double tp        = posInfo.TakeProfit();
      double slDistance = MathAbs(openPrice - sl);

      if(posInfo.PositionType() == POSITION_TYPE_BUY)
        {
         double currentProfit = symInfo.Bid() - openPrice;

         // Activate trail when profit reaches threshold
         if(currentProfit >= slDistance * InpTrailActivateRR)
           {
            double newSL = symInfo.Bid() - InpTrailStepPips;
            newSL = NormalizeDouble(newSL, _Digits);

            if(newSL > sl && newSL < symInfo.Bid())
              {
               trade.PositionModify(posInfo.Ticket(), newSL, tp);
              }
           }
        }
      else // SELL
        {
         double currentProfit = openPrice - symInfo.Ask();

         if(currentProfit >= slDistance * InpTrailActivateRR)
           {
            double newSL = symInfo.Ask() + InpTrailStepPips;
            newSL = NormalizeDouble(newSL, _Digits);

            if(newSL < sl && newSL > symInfo.Ask())
              {
               trade.PositionModify(posInfo.Ticket(), newSL, tp);
              }
           }
        }
     }
  }

//+------------------------------------------------------------------+
//| Reset daily                                                       |
//+------------------------------------------------------------------+
void ResetDaily()
  {
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.day_of_year != g_lastTradeDay)
     {
      g_todayTrades  = 0;
      g_lastTradeDay = dt.day_of_year;
      g_m15Direction  = 0;
     }
  }

//+------------------------------------------------------------------+
//| Main tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
  {
   ResetDaily();
   symInfo.RefreshRates();

   // Always manage trailing
   if(CountOpenPositions() > 0)
     {
      ManageTrailingStop();
     }

   if(!IsWithinNYSession()) return;
   if(symInfo.Spread() > InpMaxSpread) return;
   if(g_todayTrades >= InpMaxTradesPerDay) return;
   if(CountOpenPositions() > 0) return;

   // Only on new M5 bar
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   // STEP 1: Analyze M15 momentum
   g_m15Direction = AnalyzeM15Momentum();
   if(g_m15Direction == 0) return; // No strong momentum

   // STEP 2: Detect M5 fractals
   DetectM5Fractals();

   // STEP 3: Find entry fractal aligned with M15
   int fractalIdx = FindEntryFractal(g_m15Direction);
   if(fractalIdx < 0) return;

   double ask = symInfo.Ask();
   double bid = symInfo.Bid();

   // STEP 4: Execute trade
   if(g_m15Direction == 1) // LONG
     {
      double sl = g_fractals[fractalIdx].price; // SL at fractal low
      double slDistance = ask - sl;

      if(slDistance <= 0) return;

      double tp = ask + (slDistance * InpTakeProfitRR);
      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, InpTradeComment + "_LONG"))
        {
         g_todayTrades++;
         g_fractals[fractalIdx].used = true;
         Print("MTF LONG: M15 ROC=", DoubleToString(CalcM15ROC(), 2),
               " Fractal=", g_fractals[fractalIdx].price,
               " Entry=", ask, " SL=", sl, " TP=", tp);
        }
     }
   else // SHORT
     {
      double sl = g_fractals[fractalIdx].price; // SL at fractal high
      double slDistance = sl - bid;

      if(slDistance <= 0) return;

      double tp = bid - (slDistance * InpTakeProfitRR);
      sl = NormalizeDouble(sl, _Digits);
      tp = NormalizeDouble(tp, _Digits);

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, InpTradeComment + "_SHORT"))
        {
         g_todayTrades++;
         g_fractals[fractalIdx].used = true;
         Print("MTF SHORT: M15 ROC=", DoubleToString(CalcM15ROC(), 2),
               " Fractal=", g_fractals[fractalIdx].price,
               " Entry=", bid, " SL=", sl, " TP=", tp);
        }
     }
  }
