//+------------------------------------------------------------------+
//|              EA01_ORB_OpenRangeBreakout.mq5                       |
//|              NY Session Open Range Breakout - XAUUSD M5           |
//|              Scalping Strategy for New York Session                |
//+------------------------------------------------------------------+
#property copyright "Quant Strategy Suite"
#property version   "1.00"
#property description "Detects the High/Low range of the first N candles after NY open, then trades the breakout."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\SymbolInfo.mqh>

//--- Input Parameters
input group "=== SESSION FILTER ==="
input int      InpNYOpenHour      = 9;       // NY Open Hour (ET)
input int      InpNYOpenMinute    = 30;      // NY Open Minute (ET)
input int      InpNYCloseHour     = 16;      // NY Close Hour (ET)
input int      InpNYCloseMinute   = 0;       // NY Close Minute (ET)
input int      InpGMTOffset       = -5;      // Broker GMT Offset (ET = GMT-5, adjust for DST)

input group "=== ORB PARAMETERS ==="
input int      InpORBCandles      = 6;       // Number of M5 candles for Open Range (3=15min, 6=30min)
input double   InpBreakoutBuffer  = 50;      // Breakout buffer in points (filter noise)
input bool     InpUseATRFilter    = true;    // Use ATR expansion filter
input int      InpATRPeriod       = 14;      // ATR Period for volatility filter
input double   InpATRMultiplier   = 0.5;     // Min ATR expansion ratio to confirm breakout

input group "=== RISK MANAGEMENT ==="
input double   InpLotSize         = 0.01;    // Fixed Lot Size
input double   InpStopLoss        = 300;     // Stop Loss in points (opposite side of range)
input double   InpTakeProfit      = 300;     // Take Profit in points (min 1:1 RR)
input int      InpMaxTradesDay    = 3;       // Max trades per day
input int      InpMagicNumber     = 100001;  // Magic Number

input group "=== TRADE MANAGEMENT ==="
input bool     InpCloseEndSession = true;    // Close all trades at session end
input int      InpMaxSlippage     = 30;      // Max slippage in points

//--- Global Variables
CTrade         trade;
CPositionInfo  posInfo;
CSymbolInfo    symInfo;

double         g_orbHigh;
double         g_orbLow;
bool           g_orbDefined;
bool           g_buyTriggered;
bool           g_sellTriggered;
int            g_tradesToday;
datetime       g_lastDay;
int            g_atrHandle;
double         g_atrBuffer[];

//+------------------------------------------------------------------+
//| Expert initialization function                                     |
//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpMaxSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   symInfo.Name(_Symbol);

   //--- Initialize ATR
   if(InpUseATRFilter)
   {
      g_atrHandle = iATR(_Symbol, PERIOD_M5, InpATRPeriod);
      if(g_atrHandle == INVALID_HANDLE)
      {
         Print("ERROR: Failed to create ATR indicator");
         return INIT_FAILED;
      }
      ArraySetAsSeries(g_atrBuffer, true);
   }

   ResetDailyVars();

   Print("EA01 ORB initialized on ", _Symbol, " | ORB Candles: ", InpORBCandles);
   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                    |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(g_atrHandle != INVALID_HANDLE)
      IndicatorRelease(g_atrHandle);
}

//+------------------------------------------------------------------+
//| Expert tick function                                                |
//+------------------------------------------------------------------+
void OnTick()
{
   //--- Check for new day reset
   datetime currentDay = iTime(_Symbol, PERIOD_D1, 0);
   if(currentDay != g_lastDay)
   {
      ResetDailyVars();
      g_lastDay = currentDay;
   }

   //--- Get current broker time and convert to NY time
   MqlDateTime brokerTime;
   TimeToStruct(TimeCurrent(), brokerTime);

   int nyHour, nyMinute;
   BrokerToNY(brokerTime.hour, brokerTime.min, nyHour, nyMinute);
   int nyTimeMinutes = nyHour * 60 + nyMinute;

   int sessionStart = InpNYOpenHour * 60 + InpNYOpenMinute;
   int sessionEnd   = InpNYCloseHour * 60 + InpNYCloseMinute;
   int orbEnd       = sessionStart + (InpORBCandles * 5);

   //--- Close trades at session end
   if(InpCloseEndSession && nyTimeMinutes >= sessionEnd)
   {
      CloseAllPositions();
      return;
   }

   //--- Outside session: do nothing
   if(nyTimeMinutes < sessionStart || nyTimeMinutes >= sessionEnd)
      return;

   //--- New bar check
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   //--- Phase 1: Build the Open Range (during first N candles)
   if(nyTimeMinutes >= sessionStart && nyTimeMinutes < orbEnd && !g_orbDefined)
   {
      BuildOpenRange(sessionStart, nyTimeMinutes);
      return;
   }

   //--- Phase 2: Mark ORB as defined once time passes ORB window
   if(nyTimeMinutes >= orbEnd && !g_orbDefined)
   {
      FinalizeOpenRange(sessionStart);
   }

   //--- Phase 3: Trade the breakout
   if(g_orbDefined && nyTimeMinutes < sessionEnd)
   {
      TradeBreakout();
   }
}

//+------------------------------------------------------------------+
//| Build the Open Range progressively                                 |
//+------------------------------------------------------------------+
void BuildOpenRange(int sessionStartMin, int currentMin)
{
   int candlesInRange = (currentMin - sessionStartMin) / 5 + 1;
   candlesInRange = MathMin(candlesInRange, InpORBCandles);

   double high = -DBL_MAX;
   double low  = DBL_MAX;

   for(int i = 0; i < candlesInRange; i++)
   {
      double h = iHigh(_Symbol, PERIOD_M5, i);
      double l = iLow(_Symbol, PERIOD_M5, i);
      if(h > high) high = h;
      if(l < low)  low  = l;
   }

   g_orbHigh = high;
   g_orbLow  = low;
}

//+------------------------------------------------------------------+
//| Finalize the Open Range after N candles complete                    |
//+------------------------------------------------------------------+
void FinalizeOpenRange(int sessionStartMin)
{
   double high = -DBL_MAX;
   double low  = DBL_MAX;

   //--- Scan back to find the ORB candles
   for(int i = 0; i < 50; i++)
   {
      MqlDateTime barTime;
      TimeToStruct(iTime(_Symbol, PERIOD_M5, i), barTime);
      int nyH, nyM;
      BrokerToNY(barTime.hour, barTime.min, nyH, nyM);
      int barMinutes = nyH * 60 + nyM;

      if(barMinutes >= sessionStartMin && barMinutes < sessionStartMin + InpORBCandles * 5)
      {
         double h = iHigh(_Symbol, PERIOD_M5, i);
         double l = iLow(_Symbol, PERIOD_M5, i);
         if(h > high) high = h;
         if(l < low)  low  = l;
      }
   }

   if(high > -DBL_MAX && low < DBL_MAX)
   {
      g_orbHigh = high;
      g_orbLow  = low;
      g_orbDefined = true;

      double rangePoints = (g_orbHigh - g_orbLow) / _Point;
      Print("ORB DEFINED | High: ", g_orbHigh, " | Low: ", g_orbLow, 
            " | Range: ", rangePoints, " points");
   }
}

//+------------------------------------------------------------------+
//| Trade the breakout                                                 |
//+------------------------------------------------------------------+
void TradeBreakout()
{
   if(g_tradesToday >= InpMaxTradesDay) return;
   if(CountOpenPositions() > 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double point = _Point;
   double buffer = InpBreakoutBuffer * point;

   //--- ATR Filter
   if(InpUseATRFilter)
   {
      if(CopyBuffer(g_atrHandle, 0, 0, 3, g_atrBuffer) < 3) return;

      double currentATR = g_atrBuffer[0];
      double prevATR    = g_atrBuffer[2];

      if(prevATR > 0 && currentATR / prevATR < InpATRMultiplier)
         return; // Not enough volatility expansion
   }

   //--- BUY: Price breaks above ORB High + buffer
   if(!g_buyTriggered && ask > g_orbHigh + buffer)
   {
      double sl = g_orbLow - InpStopLoss * point;

      // Dynamic TP: at minimum 1:1 RR based on actual risk distance
      double riskDistance = ask - sl;
      double tp = ask + MathMax(riskDistance, InpTakeProfit * point);

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, "ORB_BUY"))
      {
         g_buyTriggered = true;
         g_tradesToday++;
         Print("ORB BUY | Entry: ", ask, " | SL: ", sl, " | TP: ", tp);
      }
   }

   //--- SELL: Price breaks below ORB Low - buffer
   if(!g_sellTriggered && bid < g_orbLow - buffer)
   {
      double sl = g_orbHigh + InpStopLoss * point;

      double riskDistance = sl - bid;
      double tp = bid - MathMax(riskDistance, InpTakeProfit * point);

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, "ORB_SELL"))
      {
         g_sellTriggered = true;
         g_tradesToday++;
         Print("ORB SELL | Entry: ", bid, " | SL: ", sl, " | TP: ", tp);
      }
   }
}

//+------------------------------------------------------------------+
//| Convert broker time to NY time                                     |
//+------------------------------------------------------------------+
void BrokerToNY(int brokerHour, int brokerMin, int &nyHour, int &nyMin)
{
   // Broker is at InpGMTOffset from GMT
   // NY is at GMT-5 (EST) or GMT-4 (EDT)
   // Simple approach: user sets InpGMTOffset to match broker-to-NY difference
   // If broker = UTC+2 and NY = UTC-5, offset = -7
   // But we let user set this directly

   int totalMinutes = brokerHour * 60 + brokerMin;
   // InpGMTOffset represents the hours to ADD to broker time to get NY time
   // If broker is UTC+2 and NY is UTC-5, InpGMTOffset = -7
   // Actually, let's simplify: InpGMTOffset = NY_UTC_offset - Broker_UTC_offset

   totalMinutes += InpGMTOffset * 60;

   // Normalize
   while(totalMinutes < 0) totalMinutes += 1440;
   while(totalMinutes >= 1440) totalMinutes -= 1440;

   nyHour = totalMinutes / 60;
   nyMin  = totalMinutes % 60;
}

//+------------------------------------------------------------------+
//| Count open positions for this EA                                   |
//+------------------------------------------------------------------+
int CountOpenPositions()
{
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
      {
