//+------------------------------------------------------------------+
#property copyright "Quant Strategy Suite"
#property version   "1.00"
#property description "Detects Fair Value Gaps and enters after liquidity sweeps at swing points."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Input Parameters
input group "=== SESSION FILTER ==="
input int      InpNYOpenHour      = 9;       // NY Open Hour (ET)
input int      InpNYOpenMinute    = 30;      // NY Open Minute (ET)
input int      InpNYCloseHour     = 16;      // NY Close Hour (ET)
input int      InpNYCloseMinute   = 0;       // NY Close Minute (ET)
input int      InpGMTOffset       = -5;      // Hours to add to broker time to get NY time

input group "=== FVG PARAMETERS ==="
input int      InpFVGLookback     = 50;      // Lookback bars to find FVGs
input double   InpMinFVGSize      = 30;      // Minimum FVG size in points
input double   InpMaxFVGSize      = 500;     // Maximum FVG size in points (filter news spikes)
input int      InpFVGMaxAge       = 40;      // Max age of FVG in bars before it expires

input group "=== LIQUIDITY SWEEP ==="
input int      InpSwingLookback   = 10;      // Bars to define swing high/low
input double   InpSweepMinPoints  = 20;      // Min points price must exceed swing to count as sweep
input double   InpSweepMaxPoints  = 200;     // Max points beyond swing (filter big moves)
input int      InpSweepConfirmBars= 2;       // Bars to confirm rejection after sweep

input group "=== RISK MANAGEMENT ==="
input double   InpLotSize         = 0.01;    // Fixed Lot Size
input double   InpStopLoss        = 250;     // Stop Loss in points (beyond sweep extreme)
input double   InpTakeProfit      = 375;     // Take Profit in points (1:1.5 RR)
input int      InpMaxTradesDay    = 4;       // Max trades per day
input int      InpMagicNumber     = 100002;  // Magic Number

input group "=== TRADE MANAGEMENT ==="
input bool     InpCloseEndSession = true;    // Close all at session end
input int      InpMaxSlippage     = 30;      // Max slippage in points

//--- Structures
struct FVG
{
   double   high;          // Upper boundary of gap
   double   low;           // Lower boundary of gap
   int      direction;     // +1 = bullish FVG (gap up), -1 = bearish FVG (gap down)
   datetime time;          // When the FVG was created
   int      barIndex;      // Bar index when created
   bool     filled;        // Whether price has filled this gap
   bool     used;          // Whether we already traded this FVG
};

struct SwingPoint
{
   double   price;
   datetime time;
   int      type;          // +1 = swing high, -1 = swing low
   bool     swept;         // Whether this swing has been swept
};

//--- Global Variables
CTrade         trade;
CPositionInfo  posInfo;

FVG            g_fvgArray[];
SwingPoint     g_swingArray[];
int            g_tradesToday;
datetime       g_lastDay;

//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpMaxSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   ArrayResize(g_fvgArray, 0);
   ArrayResize(g_swingArray, 0);
   g_tradesToday = 0;
   g_lastDay = 0;

   Print("EA02 FVG+LiqSweep initialized | FVG Lookback: ", InpFVGLookback);
   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ArrayFree(g_fvgArray);
   ArrayFree(g_swingArray);
}

//+------------------------------------------------------------------+
void OnTick()
{
   //--- Daily reset
   datetime currentDay = iTime(_Symbol, PERIOD_D1, 0);
   if(currentDay != g_lastDay)
   {
      g_tradesToday = 0;
      g_lastDay = currentDay;
   }

   //--- Session filter
   if(!IsNYSession()) 
   {
      if(InpCloseEndSession) CloseAllPositions();
      return;
   }

   //--- New bar only
   static datetime lastBar = 0;
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   if(currentBar == lastBar) return;
   lastBar = currentBar;

   //--- Step 1: Scan for new FVGs
   DetectFVGs();

   //--- Step 2: Scan for swing points
   DetectSwingPoints();

   //--- Step 3: Detect liquidity sweeps
   DetectLiquiditySweeps();

   //--- Step 4: Check for entry signals
   CheckEntrySignals();

   //--- Step 5: Clean up expired FVGs
   CleanExpiredFVGs();
}

//+------------------------------------------------------------------+
//| Detect Fair Value Gaps (3-candle pattern)                          |
//+------------------------------------------------------------------+
void DetectFVGs()
{
   // FVG = gap between candle[2].high and candle[0].low (bullish)
   //     = gap between candle[0].high and candle[2].low (bearish)
   // Candle[1] is the impulse candle that creates the gap

   for(int i = 2; i < MathMin(InpFVGLookback, 10); i++)
   {
      double high0 = iHigh(_Symbol, PERIOD_M5, i - 2);  // Most recent of the 3
      double low0  = iLow(_Symbol, PERIOD_M5, i - 2);
      double high2 = iHigh(_Symbol, PERIOD_M5, i);       // Oldest of the 3
      double low2  = iLow(_Symbol, PERIOD_M5, i);

      //--- Bullish FVG: gap between candle[2] high and candle[0] low
      if(low0 > high2)
      {
         double gapSize = (low0 - high2) / _Point;
         if(gapSize >= InpMinFVGSize && gapSize <= InpMaxFVGSize)
         {
            if(!FVGExists(high2, low0, 1))
            {
               FVG newFVG;
               newFVG.high      = low0;     // Upper bound of gap
               newFVG.low       = high2;    // Lower bound of gap
               newFVG.direction = 1;        // Bullish
               newFVG.time      = iTime(_Symbol, PERIOD_M5, i - 1);
               newFVG.barIndex  = i - 1;
               newFVG.filled    = false;
               newFVG.used      = false;

               int size = ArraySize(g_fvgArray);
               ArrayResize(g_fvgArray, size + 1);
               g_fvgArray[size] = newFVG;
            }
         }
      }

      //--- Bearish FVG: gap between candle[0] high and candle[2] low
      if(high0 < low2)
      {
         double gapSize = (low2 - high0) / _Point;
         if(gapSize >= InpMinFVGSize && gapSize <= InpMaxFVGSize)
         {
            if(!FVGExists(high0, low2, -1))
            {
               FVG newFVG;
               newFVG.high      = low2;     // Upper bound
               newFVG.low       = high0;    // Lower bound
               newFVG.direction = -1;       // Bearish
               newFVG.time      = iTime(_Symbol, PERIOD_M5, i - 1);
               newFVG.barIndex  = i - 1;
               newFVG.filled    = false;
               newFVG.used      = false;

               int size = ArraySize(g_fvgArray);
               ArrayResize(g_fvgArray, size + 1);
               g_fvgArray[size] = newFVG;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check if FVG already exists                                        |
//+------------------------------------------------------------------+
bool FVGExists(double low, double high, int dir)
{
   for(int i = 0; i < ArraySize(g_fvgArray); i++)
   {
      if(MathAbs(g_fvgArray[i].low - low) < _Point && 
         MathAbs(g_fvgArray[i].high - high) < _Point &&
         g_fvgArray[i].direction == dir)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Detect Swing Highs and Swing Lows                                  |
//+------------------------------------------------------------------+
void DetectSwingPoints()
{
   int lb = InpSwingLookback;

   // Check for swing high at bar [lb] (need lb bars on each side)
   for(int center = lb; center < lb + 5; center++)
   {
      //--- Swing High
      double centerHigh = iHigh(_Symbol, PERIOD_M5, center);
      bool isSwingHigh = true;

      for(int j = 1; j <= lb; j++)
      {
         if(iHigh(_Symbol, PERIOD_M5, center - j) >= centerHigh ||
            iHigh(_Symbol, PERIOD_M5, center + j) >= centerHigh)
         {
            isSwingHigh = false;
            break;
         }
      }

      if(isSwingHigh && !SwingExists(centerHigh, 1))
      {
         SwingPoint sp;
         sp.price = centerHigh;
         sp.time  = iTime(_Symbol, PERIOD_M5, center);
         sp.type  = 1;
         sp.swept = false;

         int size = ArraySize(g_swingArray);
         ArrayResize(g_swingArray, size + 1);
         g_swingArray[size] = sp;

         // Keep array manageable
         if(ArraySize(g_swingArray) > 50)
            ArrayRemove(g_swingArray, 0, 1);
      }

      //--- Swing Low
      double centerLow = iLow(_Symbol, PERIOD_M5, center);
      bool isSwingLow = true;

      for(int j = 1; j <= lb; j++)
      {
         if(iLow(_Symbol, PERIOD_M5, center - j) <= centerLow ||
            iLow(_Symbol, PERIOD_M5, center + j) <= centerLow)
         {
            isSwingLow = false;
            break;
         }
      }

      if(isSwingLow && !SwingExists(centerLow, -1))
      {
         SwingPoint sp;
         sp.price = centerLow;
         sp.time  = iTime(_Symbol, PERIOD_M5, center);
         sp.type  = -1;
         sp.swept = false;

         int size = ArraySize(g_swingArray);
         ArrayResize(g_swingArray, size + 1);
         g_swingArray[size] = sp;

         if(ArraySize(g_swingArray) > 50)
            ArrayRemove(g_swingArray, 0, 1);
      }
   }
}

//+------------------------------------------------------------------+
bool SwingExists(double price, int type)
{
   for(int i = 0; i < ArraySize(g_swingArray); i++)
   {
      if(MathAbs(g_swingArray[i].price - price) < _Point * 5 && g_swingArray[i].type == type)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Detect liquidity sweeps                                            |
//+------------------------------------------------------------------+
void DetectLiquiditySweeps()
{
   double currentHigh = iHigh(_Symbol, PERIOD_M5, 1);
   double currentLow  = iLow(_Symbol, PERIOD_M5, 1);
   double currentClose= iClose(_Symbol, PERIOD_M5, 1);

   for(int i = 0; i < ArraySize(g_swingArray); i++)
   {
      if(g_swingArray[i].swept) continue;

      //--- Sweep of swing high (price went above then closed below)
      if(g_swingArray[i].type == 1)
      {
         double sweepDist = (currentHigh - g_swingArray[i].price) / _Point;

         if(sweepDist >= InpSweepMinPoints && sweepDist <= InpSweepMaxPoints)
         {
            // Confirm rejection: close back below the swing high
            if(currentClose < g_swingArray[i].price)
            {
               g_swingArray[i].swept = true;
               Print("LIQUIDITY SWEEP detected at Swing High: ", g_swingArray[i].price,
                     " | Sweep distance: ", sweepDist, " pts");
            }
         }
      }

      //--- Sweep of swing low
      if(g_swingArray[i].type == -1)
      {
         double sweepDist = (g_swingArray[i].price - currentLow) / _Point;

         if(sweepDist >= InpSweepMinPoints && sweepDist <= InpSweepMaxPoints)
         {
            if(currentClose > g_swingArray[i].price)
            {
               g_swingArray[i].swept = true;
               Print("LIQUIDITY SWEEP detected at Swing Low: ", g_swingArray[i].price,
                     " | Sweep distance: ", sweepDist, " pts");
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check entry signals: Sweep + FVG confluence                        |
//+------------------------------------------------------------------+
void CheckEntrySignals()
{
   if(g_tradesToday >= InpMaxTradesDay) return;
   if(CountOpenPositions() > 0) return;

   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

   //--- Check for recently swept swing lows + bullish FVG (BUY setup)
   for(int s = 0; s < ArraySize(g_swingArray); s++)
   {
      if(!g_swingArray[s].swept) continue;
      if(g_swingArray[s].type != -1) continue; // Need swept swing low for buys

      // Find a bullish FVG nearby that price is entering
      for(int f = 0; f < ArraySize(g_fvgArray); f++)
      {
         if(g_fvgArray[f].used || g_fvgArray[f].filled) continue;
         if(g_fvgArray[f].direction != 1) continue; // Need bullish FVG

         // Price is entering the FVG zone
         if(ask <= g_fvgArray[f].high && ask >= g_fvgArray[f].low)
         {
            double sl = g_swingArray[s].price - InpStopLoss * _Point;
            double tp = ask + InpTakeProfit * _Point;

            // Ensure minimum 1:1 RR
            double risk = ask - sl;
            if(tp - ask < risk) tp = ask + risk;

            if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, "FVG_BUY_Sweep"))
            {
               g_fvgArray[f].used = true;
               g_tradesToday++;
               Print("FVG BUY after Sweep | Entry: ", ask, " | SL: ", sl, " | TP: ", tp);
               return;
            }
         }
      }
   }

   //--- Check for recently swept swing highs + bearish FVG (SELL setup)
   for(int s = 0; s < ArraySize(g_swingArray); s++)
   {
      if(!g_swingArray[s].swept) continue;
      if(g_swingArray[s].type != 1) continue; // Need swept swing high for sells

      for(int f = 0; f < ArraySize(g_fvgArray); f++)
      {
         if(g_fvgArray[f].used || g_fvgArray[f].filled) continue;
         if(g_fvgArray[f].direction != -1) continue; // Need bearish FVG

         if(bid >= g_fvgArray[f].low && bid <= g_fvgArray[f].high)
         {
            double sl = g_swingArray[s].price + InpStopLoss * _Point;
            double tp = bid - InpTakeProfit * _Point;

            double risk = sl - bid;
            if(bid - tp < risk) tp = bid - risk;

            if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, "FVG_SELL_Sweep"))
            {
               g_fvgArray[f].used = true;
               g_tradesToday++;
               Print("FVG SELL after Sweep | Entry: ", bid, " | SL: ", sl, " | TP: ", tp);
               return;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Clean expired FVGs                                                 |
//+------------------------------------------------------------------+
void CleanExpiredFVGs()
{
   for(int i = ArraySize(g_fvgArray) - 1; i >= 0; i--)
   {
      // Check if FVG is too old
      int barsAgo = iBarShift(_Symbol, PERIOD_M5, g_fvgArray[i].time);
      if(barsAgo > InpFVGMaxAge || g_fvgArray[i].used)
      {
         ArrayRemove(g_fvgArray, i, 1);
      }
      else
      {
         // Check if FVG has been filled (price passed through completely)
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         if(g_fvgArray[i].direction == 1 && bid < g_fvgArray[i].low)
            g_fvgArray[i].filled = true;
         if(g_fvgArray[i].direction == -1 && bid > g_fvgArray[i].high)
            g_fvgArray[i].filled = true;
      }
   }
}

//+------------------------------------------------------------------+
//| Session filter                                                     |
//+------------------------------------------------------------------+
bool IsNYSession()
{
   MqlDateTime brokerTime;
   TimeToStruct(TimeCurrent(), brokerTime);

   int totalMin = (brokerTime.hour + InpGMTOffset) * 60 + brokerTime.min;
   while(totalMin < 0) totalMin += 1440;
   while(totalMin >= 1440) totalMin -= 1440;

   int start = InpNYOpenHour * 60 + InpNYOpenMinute;
   int end   = InpNYCloseHour * 60 + InpNYCloseMinute;

   return (totalMin >= start && totalMin < end);
}

//+------------------------------------------------------------------+
int CountOpenPositions()
{
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   }
   return count;
}

