input bool     InpUseHigherTF     = true;    // Use M15 EMA for direction confirmation
input int      InpHTFEMAPeriod    = 20;      // M15 EMA period for trend direction

input group "=== RISK MANAGEMENT ==="
input double   InpLotSize         = 0.01;    // Fixed Lot Size
input double   InpStopLoss        = 250;     // Stop Loss in points
input double   InpTakeProfit      = 350;     // Take Profit in points
