int            g_atrFastHandle;
int            g_atrSlowHandle;
int            g_emaHTFHandle;
double         g_atrFastBuf[];
double         g_atrSlowBuf[];
double         g_emaHTFBuf[];

int            g_squeezeBars;       // Consecutive bars in squeeze
