//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpMaxSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   //--- Create indicators
   g_atrFastHandle = iATR(_Symbol, PERIOD_M5, InpATRFast);
   g_atrSlowHandle = iATR(_Symbol, PERIOD_M5, InpATRSlow);

   if(g_atrFastHandle == INVALID_HANDLE || g_atrSlowHandle == INVALID_HANDLE)
   {
      Print("ERROR: Failed to create ATR indicators");
      return INIT_FAILED;
   }

   if(InpUseHigherTF)
   {
      g_emaHTFHandle = iMA(_Symbol, PERIOD_M15, InpHTFEMAPeriod, 0, MODE_EMA, PRICE_CLOSE);
      if(g_emaHTFHandle == INVALID_HANDLE)
      {
         Print("ERROR: Failed to create M15 EMA indicator");
         return INIT_FAILED;
      }
      ArraySetAsSeries(g_emaHTFBuf, true);
