//|              EA04_ZScore_MeanReversion.mq5                        |
//|              Z-Score Dynamic Mean Reversion - XAUUSD M5           |
//|              Statistical Scalper for NY Session                    |
//+------------------------------------------------------------------+
#property copyright "Quant Strategy Suite"
#property version   "1.00"
#property description "Calculates Z-Score of price vs VWAP-like rolling mean, trades reversion at extreme Z values."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//--- Input Parameters
input group "=== SESSION FILTER ==="
input int      InpNYOpenHour      = 9;
input int      InpNYOpenMinute    = 30;
input int      InpNYCloseHour     = 16;
input int      InpNYCloseMinute   = 0;
input int      InpGMTOffset       = -5;

input group "=== Z-SCORE PARAMETERS ==="
input int      InpZPeriod         = 20;      // Rolling window for mean & std dev
input double   InpZEntry          = 2.0;     // Z-Score threshold for entry (±2σ)
input double   InpZExit           = 0.5;     // Z-Score target for exit (return to ±0.5σ)
input double   InpZStopLevel      = 3.0;     // Z-Score level for stop loss (±3σ)
input bool     InpUseVWAP         = true;    // Use volume-weighted mean (true) or simple (false)
input bool     InpUseTickVol      = true;    // Use tick volume as proxy (true) or real vol (false)

input group "=== FILTERS ==="
