input double   InpMaxStdDev       = 500;     // Max std dev in points (avoid news/chaos)
input int      InpCooldownBars    = 3;       // Bars to wait after a trade before re-entry
input bool     InpFilterTrend     = true;    // Filter: don't counter-trade strong trends
input double   InpTrendZThresh    = 3.5;     // Z-Score above this = strong trend, no fade

input group "=== RISK MANAGEMENT ==="
input double   InpLotSize         = 0.01;    // Fixed Lot Size
input double   InpStopLoss        = 300;     // Fixed SL in points (backup if Z-stop is wider)
input double   InpTakeProfit      = 300;     // Fixed TP in points (backup if Z-target is wider)
input int      InpMaxTradesDay    = 5;       // Max trades per day
input int      InpMagicNumber     = 100004;  // Magic Number

input group "=== TRADE MANAGEMENT ==="
input bool     InpCloseEndSession = true;
input int      InpMaxSlippage     = 30;

//--- Global Variables
