int OnInit()
{
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(InpMaxSlippage);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   g_tradesToday   = 0;
   g_lastDay       = 0;
   g_cooldownCount = 0;
   g_lastZScore    = 0;
   g_inPosition    = false;
   g_positionDir   = 0;

   Print("EA04 Z-Score MeanReversion initialized | Z-Entry: ±", InpZEntry,
         " | Z-Exit: ±", InpZExit, " | Period: ", InpZPeriod);
   return INIT_SUCCEEDED;
