   ArrayResize(prices, period);
   ArrayResize(volumes, period);

   //--- Collect data (using completed bars, starting from bar 1)
   for(int i = 0; i < period; i++)
   {
      // Use typical price: (H+L+C)/3
      double h = iHigh(_Symbol, PERIOD_M5, i + 1);
      double l = iLow(_Symbol, PERIOD_M5, i + 1);
      double c = iClose(_Symbol, PERIOD_M5, i + 1);
      prices[i] = (h + l + c) / 3.0;

