            volumes[i] = (double)iTickVolume(_Symbol, PERIOD_M5, i + 1);
         else
            volumes[i] = (double)iRealVolume(_Symbol, PERIOD_M5, i + 1);

         if(volumes[i] <= 0) volumes[i] = 1; // Prevent division by zero
      }
      else
      {
         volumes[i] = 1.0; // Equal weight = simple mean
      }
   }

   //--- Calculate volume-weighted mean
   double sumPV = 0, sumV = 0;
   for(int i = 0; i < period; i++)
   {
      sumPV += prices[i] * volumes[i];
      sumV  += volumes[i];
   }

   if(sumV <= 0) return false;
   mean = sumPV / sumV;

   //--- Calculate standard deviation (volume-weighted)
   double sumSqDiff = 0;
   for(int i = 0; i < period; i++)
   {
      double diff = prices[i] - mean;
      sumSqDiff += diff * diff * volumes[i];
   }

   stdDev = MathSqrt(sumSqDiff / sumV);

   if(stdDev <= 0) return false;

   //--- Current price Z-Score
   double currentPrice = iClose(_Symbol, PERIOD_M5, 1); // Last completed bar
   zScore = (currentPrice - mean) / stdDev;

   return true;
