//| Check for new entry signals                                        |
//+------------------------------------------------------------------+
void CheckEntry(double zScore, double mean, double stdDev)
{
   if(g_tradesToday >= InpMaxTradesDay) return;

   //--- Trend filter: don't fade extreme trends
   if(InpFilterTrend && MathAbs(zScore) > InpTrendZThresh)
   {
      Print("Z-Score too extreme (", DoubleToString(zScore, 2), 
            ") - possible trend, skipping");
      return;
   }

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double point = _Point;

   //--- SELL: Z-Score above +entry threshold (overbought, expect reversion down)
   if(zScore >= InpZEntry)
   {
      // SL at Z-stop level or fixed, whichever is tighter
      double zStopPrice = mean + InpZStopLevel * stdDev;
      double fixedStop  = bid + InpStopLoss * point;
      double sl = MathMin(zStopPrice, fixedStop);

      // TP at Z-exit level or fixed
      double zTargetPrice = mean + InpZExit * stdDev;
      double fixedTP      = bid - InpTakeProfit * point;
      double tp = MathMax(zTargetPrice, fixedTP); // Less aggressive of the two

      // Ensure min 1:1 RR
      double risk   = sl - bid;
      double reward = bid - tp;
      if(reward < risk) tp = bid - risk;

      if(trade.Sell(InpLotSize, _Symbol, bid, sl, tp, 
         StringFormat("ZSCORE_SELL_%.1f", zScore)))
      {
