               " | Entry: ", bid, " | SL: ", sl, " | TP: ", tp);
      }
   }

   //--- BUY: Z-Score below -entry threshold (oversold, expect reversion up)
   if(zScore <= -InpZEntry)
   {
      double zStopPrice = mean - InpZStopLevel * stdDev;
      double fixedStop  = ask - InpStopLoss * point;
      double sl = MathMax(zStopPrice, fixedStop);

      double zTargetPrice = mean - InpZExit * stdDev;
      double fixedTP      = ask + InpTakeProfit * point;
      double tp = MathMin(zTargetPrice, fixedTP);

      double risk   = ask - sl;
      double reward = tp - ask;
      if(reward < risk) tp = ask + risk;

      if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp,
         StringFormat("ZSCORE_BUY_%.1f", zScore)))
      {
