//+------------------------------------------------------------------+
//| Evaluate M15 Rate of Change for momentum                           |
//+------------------------------------------------------------------+
void EvaluateM15Momentum()
{
   //--- Calculate raw ROC on M15
   double closeNow  = iClose(_Symbol, PERIOD_M15, 1);  // Last completed M15 bar
   double closePrev = iClose(_Symbol, PERIOD_M15, 1 + InpROCPeriod);

   if(closePrev <= 0) { g_m15Direction = 0; return; }

   g_m15ROC = ((closeNow - closePrev) / closePrev) * 100.0;

   if(InpUseNormalizedROC)
   {
      //--- Normalize ROC: calculate z-score of current ROC vs historical ROC
      double rocValues[];
      ArrayResize(rocValues, InpROCNormPeriod);

      for(int i = 0; i < InpROCNormPeriod; i++)
      {
         double c1 = iClose(_Symbol, PERIOD_M15, i + 1);
         double c2 = iClose(_Symbol, PERIOD_M15, i + 1 + InpROCPeriod);
         if(c2 > 0)
            rocValues[i] = ((c1 - c2) / c2) * 100.0;
         else
            rocValues[i] = 0;
      }

      // Mean and StdDev of ROC
      double sum = 0, sumSq = 0;
      for(int i = 0; i < InpROCNormPeriod; i++) sum += rocValues[i];
      double mean = sum / InpROCNormPeriod;

      for(int i = 0; i < InpROCNormPeriod; i++) sumSq += (rocValues[i] - mean) * (rocValues[i] - mean);
      double stdDev = MathSqrt(sumSq / InpROCNormPeriod);

      if(stdDev > 0)
         g_m15ROCNorm = (g_m15ROC - mean) / stdDev;
      else
         g_m15ROCNorm = 0;

      // Direction from normalized ROC
      if(g_m15ROCNorm > InpROCNormThresh)       g_m15Direction = 1;
