//| Track pullback and enter when price retests fractal level          |
//+------------------------------------------------------------------+
void TradeExpansion(){}  // Not used in this EA

void TrackPullbackAndEnter(bool fractalFound, FractalPoint &fractal)
{
   if(g_tradesToday >= InpMaxTradesDay) return;
   if(CountOpenPositions() > 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double point = _Point;

   //--- If new fractal found, start tracking pullback
   if(fractalFound)
   {
      g_pullbackActive  = true;
      g_pullbackDir     = g_m15Direction;
      g_pullbackBars    = 0;
      g_pullbackExtreme = fractal.price;

      Print("Fractal detected | Type: ", (fractal.type == 1 ? "HIGH" : "LOW"),
            " | Price: ", fractal.price, " | M15 Dir: ", g_m15Direction);
   }

   //--- Track active pullback
   if(!g_pullbackActive) return;

   g_pullbackBars++;

   //--- Check expiry
   if(g_pullbackBars > InpMaxPullbackBars)
   {
      g_pullbackActive = false;
      return;
   }

   //--- BUY: M15 bullish, price pulled back to fractal low, now resuming
   if(g_pullbackDir == 1)
   {
      double currentLow = iLow(_Symbol, PERIOD_M5, 1);
      double pullbackDepth = (iHigh(_Symbol, PERIOD_M5, 
         iHighest(_Symbol, PERIOD_M5, MODE_HIGH, g_pullbackBars + 3, 1)) - currentLow) / point;

      // Validate pullback depth
      if(pullbackDepth < InpMinPullbackPts || pullbackDepth > InpMaxPullbackPts) return;

      // Entry condition: price near fractal low and current bar is bullish (close > open)
      double closeBar1 = iClose(_Symbol, PERIOD_M5, 1);
      double openBar1  = iOpen(_Symbol, PERIOD_M5, 1);

      if(MathAbs(currentLow - g_pullbackExtreme) < InpMinPullbackPts * point * 2 &&
         closeBar1 > openBar1) // Bullish confirmation bar
      {
         double sl = g_pullbackExtreme - InpSLBuffer * point;

         // TP: find next structure level or use fixed
         double structureTP = FindStructureLevel(1);
         double fixedTP = ask + InpTakeProfit * point;
         double tp = (structureTP > 0) ? MathMin(structureTP, fixedTP) : fixedTP;

         // Ensure min 1:1 RR
         double risk = ask - sl;
         if(tp - ask < risk) tp = ask + risk;

         if(risk > 0 && risk < InpStopLoss * point * 2)
         {
            if(trade.Buy(InpLotSize, _Symbol, ask, sl, tp, "MTF_BUY"))
            {
