                     " | Fractal: ", g_pullbackExtreme,
                     " | Entry: ", bid, " | SL: ", sl, " | TP: ", tp);
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Find next structure level for TP target                            |
//+------------------------------------------------------------------+
double FindStructureLevel(int direction)
{
   double currentPrice = iClose(_Symbol, PERIOD_M5, 1);
   int lb = InpStructureLookback;

   if(direction == 1) // Looking for resistance above
   {
      double bestLevel = 0;
      double minDist = DBL_MAX;

      for(int center = InpFractalBars; center < lb; center++)
      {
         double h = iHigh(_Symbol, PERIOD_M5, center);
         bool isSwingHigh = true;

         for(int j = 1; j <= InpFractalBars && isSwingHigh; j++)
         {
            if(center - j >= 0 && iHigh(_Symbol, PERIOD_M5, center - j) >= h) isSwingHigh = false;
            if(iHigh(_Symbol, PERIOD_M5, center + j) >= h) isSwingHigh = false;
         }

         if(isSwingHigh && h > currentPrice)
         {
            double dist = (h - currentPrice) / _Point;
            if(dist >= InpMinStructureDist && dist < minDist)
            {
               minDist = dist;
               bestLevel = h;
            }
         }
      }
      return bestLevel;
   }
   else // Looking for support below
   {
      double bestLevel = 0;
      double minDist = DBL_MAX;

      for(int center = InpFractalBars; center < lb; center++)
      {
         double l = iLow(_Symbol, PERIOD_M5, center);
         bool isSwingLow = true;

         for(int j = 1; j <= InpFractalBars && isSwingLow; j++)
         {
            if(center - j >= 0 && iLow(_Symbol, PERIOD_M5, center - j) <= l) isSwingLow = false;
            if(iLow(_Symbol, PERIOD_M5, center + j) <= l) isSwingLow = false;
         }

         if(isSwingLow && l < currentPrice)
         {
            double dist = (currentPrice - l) / _Point;
            if(dist >= InpMinStructureDist && dist < minDist)
            {
               minDist = dist;
               bestLevel = l;
            }
         }
      }
      return bestLevel;
   }
}

//+------------------------------------------------------------------+
bool IsNYSession()
{
   MqlDateTime bt;
   TimeToStruct(TimeCurrent(), bt);
   int totalMin = (bt.hour + InpGMTOffset) * 60 + bt.min;
   while(totalMin < 0) totalMin += 1440;
   while(totalMin >= 1440) totalMin -= 1440;
   return (totalMin >= InpNYOpenHour * 60 + InpNYOpenMinute && 
           totalMin < InpNYCloseHour * 60 + InpNYCloseMinute);
}

//+------------------------------------------------------------------+
int CountOpenPositions()
{
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            count++;
   }
   return count;
}

//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            trade.PositionClose(posInfo.Ticket());
   }
}
